module axi_alu (
    input  wire        axi_clk_in,
    input  wire        fast_clk_in,
    input  wire        reset_in,

    // AXI Interface
    input  wire        axi_awvalid_i,
    input  wire        axi_wvalid_i,
    input  wire        axi_bready_i,
    input  wire        axi_arvalid_i,
    input  wire        axi_rready_i,

    output wire        axi_awready_o,
    output wire        axi_wready_o,
    output wire        axi_bvalid_o,
    output wire        axi_arready_o,
    output wire        axi_rvalid_o,

    input  wire [31:0] axi_awaddr_i,
    input  wire [31:0] axi_wdata_i,
    input  wire [31:0] axi_araddr_i,

    input  wire [3:0]  axi_wstrb_i,
    output wire [31:0] axi_rdata_o,
    output wire [63:0] result_o
);

    wire        clk;
    wire [31:0] operand_a, operand_b, operand_c;
    wire [1:0]  op_select;
    wire        start, clock_control;
    wire [31:0] data_a;
    wire [31:0] data_b;
    wire [31:0] data_c;

    wire [31:0] operand_a_cdc, operand_b_cdc, operand_c_cdc;
    wire [1:0]  op_select_cdc;
    wire        start_cdc;
    wire [31:0] operand_a_sync, operand_b_sync, operand_c_sync;
    wire [1:0]  op_select_sync;
    wire        start_sync;

    clock_control u_clock_control (
        .axi_clk_in  (axi_clk_in),
        .fast_clk_in (fast_clk_in),
        .clk_ctrl    (clock_control),
        .clk         (clk)
    );

    axi_csr_block u_axi_csr_block (
        .axi_aclk_i    (axi_clk_in),
        .axi_areset_i  (reset_in),
        .axi_awvalid_i   (axi_awvalid_i),
        .axi_awready_o   (axi_awready_o),
        .axi_awaddr_i    (axi_awaddr_i),
        .axi_wvalid_i    (axi_wvalid_i),
        .axi_wready_o    (axi_wready_o),
        .axi_wdata_i     (axi_wdata_i),
        .axi_wstrb_i     (axi_wstrb_i),
        .axi_bvalid_o    (axi_bvalid_o),
        .axi_bready_i    (axi_bready_i),
        .axi_arvalid_i   (axi_arvalid_i),
        .axi_arready_o   (axi_arready_o),
        .axi_araddr_i    (axi_araddr_i),
        .axi_rvalid_o    (axi_rvalid_o),
        .axi_rready_i    (axi_rready_i),
        .axi_rdata_o     (axi_rdata_o),
        .operand_a     (operand_a_cdc),
        .operand_b     (operand_b_cdc),
        .operand_c     (operand_c_cdc),
        .op_select     (op_select_cdc),
        .start         (start_cdc),
        .clock_control (clock_control)
    );

    // CDC logic is only active when clock_control is HIGH
    assign operand_a = (clock_control) ? operand_a_sync : operand_a_cdc;
    assign operand_b = (clock_control) ? operand_b_sync : operand_b_cdc;
    assign operand_c = (clock_control) ? operand_c_sync : operand_c_cdc;
    assign op_select = (clock_control) ? op_select_sync : op_select_cdc;
    assign start     = (clock_control) ? start_sync : start_cdc;

    // CDC Synchronizers (only used when fast_clk is selected)
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_a (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_a_cdc), .data_out(operand_a_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_b (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_b_cdc), .data_out(operand_b_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_c (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_c_cdc), .data_out(operand_c_sync));
    cdc_synchronizer #(.WIDTH(2))  u_cdc_op_select  (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(op_select_cdc), .data_out(op_select_sync));
    cdc_synchronizer #(.WIDTH(1))  u_cdc_start      (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(start_cdc), .data_out(start_sync));

    memory_block u_memory_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .address_a  (operand_a[5:0]),
        .address_b  (operand_b[5:0]),
        .address_c  (operand_c[5:0]),
        .data_a     (data_a),
        .data_b     (data_b),
        .data_c     (data_c)
    );

    dsp_block u_dsp_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .operand_a  (data_a),
        .operand_b  (data_b),
        .operand_c  (data_c),
        .op_select  (op_select),
        .start      (start),
        .result     (result_o)
    );

endmodule

// ------------------------------------------------------------------
// CDC Synchronizer Module (Double Flop Synchronization)
// ------------------------------------------------------------------
module cdc_synchronizer #(parameter WIDTH = 1) (
    input wire clk_src,  // Source clock
    input wire clk_dst,  // Destination clock
    input wire reset_in, // Reset signal
    input wire [WIDTH-1:0] data_in,  // Data from source domain
    output reg [WIDTH-1:0] data_out  // Synchronized data in destination domain
);
    reg [WIDTH-1:0] data_sync_1, data_sync_2;

    always @(posedge clk_dst or posedge reset_in) begin
        if (reset_in) begin
            data_sync_1 <= {WIDTH{1'b0}};
            data_sync_2 <= {WIDTH{1'b0}};
            data_out    <= {WIDTH{1'b0}};
        end else begin
            data_sync_1 <= data_in;   // First stage
            data_sync_2 <= data_sync_1; // Second stage
            data_out    <= data_sync_2; // Stable output
        end
    end
endmodule

// ------------------------------------------------------------------
// Clock Control Module
// ------------------------------------------------------------------
module clock_control (
    input  wire axi_clk_in,
    input  wire fast_clk_in,
    input  wire clk_ctrl,
    output wire clk
);
    assign clk = clk_ctrl ? fast_clk_in : axi_clk_in;
endmodule

// ------------------------------------------------------------------
// AXI-to-CSR Register Block (With Write Response Handling)
// ------------------------------------------------------------------
module axi_csr_block (
    input  wire        axi_aclk_i,
    input  wire        axi_areset_i,

    // AXI Write Address Channel
    input  wire        axi_awvalid_i,
    output reg         axi_awready_o,
    input  wire [31:0] axi_awaddr_i,

    // AXI Write Data Channel
    input  wire        axi_wvalid_i,
    output reg         axi_wready_o,
    input  wire [31:0] axi_wdata_i,
    input  wire [3:0]  axi_wstrb_i,

    // AXI Write Response Channel (FIXED)
    output reg         axi_bvalid_o,
    input  wire        axi_bready_i,

    // AXI Read Address Channel
    input  wire        axi_arvalid_i,
    output reg         axi_arready_o,
    input  wire [31:0] axi_araddr_i,

    // AXI Read Data Channel
    output reg         axi_rvalid_o,
    input  wire        axi_rready_i,
    output reg  [31:0] axi_rdata_o,

    // CSR Outputs
    output reg  [31:0] operand_a,
    output reg  [31:0] operand_b,
    output reg  [31:0] operand_c,
    output reg  [1:0]  op_select,
    output reg         start,
    output reg         clock_control
);
    reg [31:0] csr_reg [0:4];

    always @(posedge axi_aclk_i or posedge axi_areset_i) begin
        if (axi_areset_i) begin
            operand_a     <= 32'd0;
            operand_b     <= 32'd0;
            operand_c     <= 32'd0;
            op_select     <= 2'd0;
            start         <= 1'b0;
            clock_control <= 1'b0;
            axi_awready_o <= 0;
            axi_wready_o  <= 0;
            axi_bvalid_o  <= 0; // Set response valid
            axi_arready_o <= 0;
            axi_rvalid_o  <= 0;
            axi_rdata_o   <= 32'd0;
            csr_reg[0]    <= 32'd0;
            csr_reg[1]    <= 32'd0;
            csr_reg[2]    <= 32'd0;
            csr_reg[3]    <= 32'd0;
            csr_reg[4]    <= 32'd0;
        end else begin
            // Handle AXI Write
            if (axi_awvalid_i && axi_wvalid_i) begin
                csr_reg[axi_awaddr_i[4:2]] <= axi_wdata_i;
                axi_awready_o <= 1;
                axi_wready_o  <= 1;
                axi_bvalid_o  <= 1; // Set response valid
            end else begin
                axi_awready_o <= 0;
                axi_wready_o  <= 0;
                axi_bvalid_o  <= 0; // Set response valid
            end

            // Handle Write Response
            if (axi_bvalid_o && axi_bready_i) begin
                axi_bvalid_o <= 0; // Clear response once acknowledged
            end

            // Handle AXI Read
            if (axi_arvalid_i) begin
                axi_arready_o <= 1;
                axi_rvalid_o  <= 1;
                axi_rdata_o    <= csr_reg[axi_araddr_i[4:2]];
            end else begin
                axi_arready_o <= 0;
                axi_rvalid_o  <= 0;
            end

            // Update CSR Registers
            operand_a     <= csr_reg[0];
            operand_b     <= csr_reg[1];
            operand_c     <= csr_reg[2];
            op_select     <= csr_reg[3][1:0];
            start         <= csr_reg[3][2];
            clock_control <= csr_reg[4][0];
        end
    end
endmodule

// ------------------------------------------------------------------
// Memory Block (ROM)
// ------------------------------------------------------------------
module memory_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [5:0]  address_a,
    input  wire [5:0]  address_b,
    input  wire [5:0]  address_c,
    output wire [31:0] data_a,
    output wire [31:0] data_b,
    output wire [31:0] data_c
);
    reg [31:0] rom [0:63];

    initial begin
        $readmemh("../rom_data.mem", rom);
    end

    assign data_a = (reset_in) ? 32'd0 : rom[address_a];
    assign data_b = (reset_in) ? 32'd0 : rom[address_b];
    assign data_c = (reset_in) ? 32'd0 : rom[address_c];
endmodule

// ------------------------------------------------------------------
// DSP Processing Block
// ------------------------------------------------------------------
module dsp_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [31:0] operand_a,
    input  wire [31:0] operand_b,
    input  wire [31:0] operand_c,
    input  wire [1:0]  op_select,
    input  wire        start,
    output reg  [63:0] result
);
    always @(posedge clk or posedge reset_in) begin
        if (reset_in)
            result <= 64'd0;
        else begin
            if (start) begin
                case (op_select)
                    2'b00: result <= (operand_a + operand_b) * operand_c;    // MAC
                    2'b01: result <= operand_a * operand_b;    // Multiplication
                    2'b10: result <= operand_a >> operand_b[4:0]; // Shift Right
                    2'b11: result <= operand_b ? operand_a / operand_b : 64'hDEADDEAD; // Division (handle divide by zero)
                endcase
            end
        end
    end
endmodule

output.rtl/axi_alu.sv:
module axi_alu (
    input  wire        axi_clk_in,
    input  wire        fast_clk_in,
    input  wire        reset_in,
    input  wire*     axi_awvalid_i,
    input  wire*     axi_wvalid_i,

    output wire*      axi_awready_o,
    output wire*      axi_wready_i,
    output wire*      axi_bvalid_o,
    output wire*      axi_rvalid_o,
    output wire*      result_o
);

    wire        clock_control;
    wire [31:0]  operand_a,
    wire [31:0]  operand_b,
    wire [31:0]  operand_c,
    wire [1:0]   op_select,
    wire        start;

    // AXI interface
    axi_csr_block (
        .axi_a (operand_a_cdc),
        .axi_wvalid_i (axi_wvalid_i),
        .axi_wready_o (axi_wready_o),
        .axi_bvalid_i (axi_bvalid_i),
        .axi_arvalid_i (axi_arvalid_i),
        .axi_arready_o (axi_arready_o),
        .axi_rvalid_o (axi_rvalid_o),
        .result_o (result_o)
    );

    // AXI to CSR
    axi_csr_block (
        .axi_a (operand_a_cdc),
        .axi_areset_i (reset_in),
        .axi_awvalid_i (axi_awvalid_i),
        .axi_wvalid_i (axi_wvalid_i),
        .axi_wstrb_i (axi_wstrb_i),
        .axi_bvalid_i (axi_bvalid_i),
        .axi_arvalid_i (axi_arvalid_i),
        .axi_arstrb_i (axi_arstrb_i),
        .axi_rvalid_i (axi_rvalid_i),
        .operand_a     (operand_a_cdc),
        .operand_b     (operand_b_cdc),
        .operand_c     (operand_c_cdc),
        .op_select     (op_select),
        .start         (start),
        .clock_control (clock_control)
    );

    // DSP processing
    dsp_block (
        .clk (clk),
        .reset_in (reset_in),
        .operand_a (operand_a_cdc),
        .operand_b (operand_b_cdc),
        .operand_c (operand_c_cdc),
        .op_select (op_select),
        .start (start),
        .result (result_o)
    );

    // Memory block
    memory_block (
        .clk (clk),
        .reset_in (reset_in),
        .address_a (operand_a_addr),
        .address_b (operand_b_addr),
        .address_c (operand_c_addr),
        .data_a (data_a),
        .data_b (data_b),
        .data_c (data_c)
    );

    // CSR outputs
    output reg [31:0] operand_a_addr, operand_b_addr, operand_c_addr;
    output reg [1:0]  op_select;
    output reg        start;
    output reg        clock_control;
    output reg [31:0] result;

    // Initializations
    always @(posedge axi_clk_in or posedge fast_clk_in or posedge reset_in) begin
        if (reset_in) begin
            operand_a_addr <= 32'd0;
            operand_b_addr <= 32'd0;
            operand_c_addr <= 32'd0;
            op_select <= 2'b00;
            start <= 1'b0;
            clock_control <= 1'b0;
            result <= 32'd0;
            $readmemh("../rom_data.mem", rom);
        end else begin
            operand_a_addr <= 32'd0;
            operand_b_addr <= 32'd0;
            operand_c_addr <= 32'd0;
            op_select <= 2'b00;
            start <= 1'b0;
            clock_control <= 1'b0;
            result <= 32'd0;
        end
    end
endmodule

output.rtl/axi_register.sv:
module axi_register(
    input clock,
    input rst,
    input [ADDR_WIDTH-1:0] awaddr,
    input [DATA_WIDTH-1:0] wdata,
    input [DATA_WIDTH-1:0] wstrb,
    input wvalid,
    input bready,
    input [ADDR_WIDTH-1:0] araddr,
    input arvalid,
    input rvalid,
    input done,
    output [1:0] bresp,
    output bvalid,
    output [1:0] rresp,
    output rvalid_o,
    output rdata,
    output start_o,
    output beat_o,
    output [19:0] beat,
    output writeback_o,
    output [31:0] id_reg
);

    // AXI4-Lite protocol handshake
    reg valid_ar, valid_aw, arvalid_o, awvalid_o;

    // Address decoding
    reg [ADDR_WIDTH-1:0] address;

    // Register mappings
    reg [20:0] beat_reg;
    reg start_reg;
    reg [31:0] id_reg;
    // ... (other registers as needed)

    // Address phase for write
    always_comb begin
        if (rst) begin
            valid_ar = 1;
            valid_aw = 1;
            arvalid_o = 0;
            awvalid_o = 0;
        else if (arvalid) begin
            valid_ar = 0;
            arvalid_o = 0;
        end else if (awvalid) begin
            valid_aw = 0;
            awvalid_o = 0;
        end else begin
            valid_ar = 0;
            valid_aw = 0;
        end
    end

    // Data phase for write
    always_comb begin
        if (valid_aw && wvalid && (wstrb == (1 << DATA_WIDTH))) begin
            beat_reg = (wdata >> 12) | (wdata << 12);
            start_reg = (wdata & 1);
            beat_o = beat_reg;
            start_o = start_reg;
            writeback_o = start_reg;
            bvalid = 1;
        end else if (valid_aw && wvalid) begin
            bvalid = 0;
        end
    end

    // Address phase for read
    always_comb begin
        if (rst) begin
            valid_ar = 1;
            valid_aw = 1;
            arvalid_o = 0;
            awvalid_o = 0;
        else if (arvalid) begin
            valid_ar = 0;
            arvalid_o = 0;
        end else if (awvalid) begin
            valid_aw = 0;
            awvalid_o = 0;
        end else begin
            valid_ar = 0;
            valid_aw = 0;
        end
    end

    // Data phase for read
    always_comb begin
        if (valid_ar && arvalid) begin
            address = araddr;
            rdata_o = (id_reg >> (DATA_WIDTH - 1)) | (id_reg << (DATA_WIDTH - 1));
            rvalid_o = 1;
            rvalid = 1;
        end else if (valid_ar && arvalid) begin
            rvalid_o = 0;
        end
    end

    // Completion phase for write
    always_comb begin
        if (rst) begin
            bvalid_o = 0;
            bresp_o = 0b00;
        else if (bvalid) begin
            bvalid_o = 0;
            bresp_o = (bvalid && (start_reg == 1)) ? 2'b10 : 2'b00;
        else begin
            bvalid_o = 1;
        end
    end

    // Completion phase for read
    always_comb begin
        if (rst) begin
            rvalid_o = 0;
            rresp_o = 0b00;
        else if (rvalid) begin
            rvalid_o = 0;
            rresp_o = (rvalid && (done == 1)) ? 2'b10 : 2'b00;
        else begin
            rvalid_o = 1;
        end
    end

    // Reset handling
    always_comb begin
        if (rst) begin
            beat_o = 0;
            start_o = 0;
            writeback_o = 0;
            id_reg = 0x00010001;
            beat_reg = 0;
            rdata_o = 0;
            rvalid_o = 0;
            bvalid_o = 0;
            bresp_o = 0b00;
            rresp_o = 0b00;
            arvalid_o = 0;
            awvalid_o = 0;
        else begin
            beat_o = beat_reg;
            start_o = start_reg;
            writeback_o = start_reg;
            id_reg = 0x00010001;
            beat_reg = 0;
            rdata_o = 0;
            rvalid_o = 0;
            bvalid_o = 0;
            bresp_o = 0b00;
            rresp_o = 0b00;
            arvalid_o = 0;
            awvalid_o = 0;
        end
    end
endmodule

output.rtl/axis_resize.sv:
module axis_resize (
  inputclk,          //Global clock signal: Signals are sampled on the rising edge of clk
  inputresetn,       //The global reset signal: resetn is synchronous active-LOW reset.
  input s_valid,     //The s_axis_valid signal indicates that the slave is driving a valid transfer.
  input [15:0] s_data, //The s_axis_data is the primary payload data from slave.
  output reg s_ready, //The s_axis_ready indicates that the slave can accept a transfer in the current cycle.
  input m_ready,      //The m_axis_ready indicates that the slave can accept a transfer in the current cycle.
  output reg [7:0] m_data //The m_axis_data is the primary payload data to master.
);

  reg state = 0; // 0: reset, 1: waiting for first byte, 2: waiting for second byte, 3: done

  always @posedge clk begin
    case(state)
      0:
        if (resetn)
          m_data = 0;
          m_valid = 0;
          s_ready = 0;
          state = 1;
        else if (m_ready)
          state = 1;
      1:
        if (s_valid)
          m_data = s_data[7:0];
          state = 2;
      2:
        if (s_valid)
          m_data = (s_data[15:8] << 8) | m_data;
          m_valid = 1;
          s_ready = 1;
          state = 3;
      3:
        // No action needed, wait for next cycle
      endcase
    end
  endmodule

endmodule

output.rtl/axis_upscale.sv:
module axis_upscale(
    input clock,
    input resetn,
    input dfmt_enable,
    input dfmt_type,
    input dfmt_se,
    input s_axis_valid,
    input s_axis_data,
    output m_axis_valid,
    output m_axis_data
);
    // Flip-flop chain for data storage and shifting
    reg [23:0] data_reg;
    // Flip-flop for sign extension
    reg sign_ext;

    // Initialize flip-flops to 0
    always @* resetn ? data_reg <= 24'b0 : data_reg;

    // Shift input data into flip-flop chain
    always @* positive_edge clock begin
        if (s_axis_valid) begin
            data_reg[23] = s_axis_data[23];
            for (int i = 22; i >= 0; i--) begin
                data_reg[i] = data_reg[i+1];
            end
        end
    end
    // Determine sign extension
    always @* positive_edge clock begin
        if (dfmt_enable && dfmt_se) begin
            sign_ext = data_reg[0];
        else begin
            sign_ext = 0;
        end
    end
    // Construct output based on data format type
    always @* positive_edge clock begin
        if (dfmt_type) begin
            m_axis_data[31] = sign_ext;
            m_axis_data[23:0] = data_reg;
        else begin
            m_axis_data[23] = data_reg[23];
            m_axis_data[22:0] = data_reg[21:0];
            m_axis_data[31] = 0;
        end
    end
    // Set master valid when done
    always @* positive_edge clock begin
        m_axis_valid = 1;
    end
endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32
)(
    input           clk_i,
    input           rst_i,
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    input           inport_awready_o,
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    input           inport_wready_o,
    input           inport_bready_i,
    input          inport_bvalid_i,
    output          inport_bresp_o,
    output [1:0]    inport_rresp_o,
    output          inport_arvalid_o,
    output          inport_arready_o,
    output  [ADDR_WIDTH-1:0]   inport_araddr_o,
    output          inport_rvalid_o,
    output  [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,
    output          outport_awready_i,
    output          outport_awvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_awaddr_o,
    output          outport_wvalid_o,
    output  [DATA_WIDTH-1:0]   outport_wdata_o,
    output  [3:0]    outport_wstrb_o,
    output          outport_wready_o,
    output          outport_bvalid_i,
    output [1:0]    outport_bresp_i,
    output          outport_bready_o,
    output  [ADDR_WIDTH-1:0]   outport_araddr_o,
    output          outport_rvalid_o,
    output  [DATA_WIDTH-1:0]   outport_rdata_o,
    output [1:0]    outport_rresp_o,
    output          outport_rready_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output  [DATA_WIDTH-1:0]   outport_wdata_o,
    output  [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_wresp_i,
    input           outport_wresp_o,
    output          outport_wvalid_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input  [1:0]    outport_rresp_i,
    input           outport_rresp_o,
    output          outport_rvalid_o,
    output  [DATA_WIDTH-1:0]   outport_rdata_o,

    //Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output  [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output  [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_peripheral0_bresp_i,
    input           outport_peripheral0_bvalid_i,
    output          outport_peripheral0_bready_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input  [1:0]    outport_peripheral0_rresp_i,
    input           outport_peripheral0_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    output          outport_peripheral0_rready_o
);

`define ADDR_ELSE 0
`define PERIPH0_ADDR 0x80000000
`define PERIPH0_MASK 0x80000000

// Read Port
reg [3:0]       read_pending_q;
reg [3:0]       read_pending_r;
reg [`ADDR_ELSE-1:0] read_port_q;
reg [`ADDR_ELSE-1:0] read_port_r;

wire read_accept_w       = (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);

always @ (posedge clk_i)
if (rst_i)
begin
    read_pending_q <= 4'h0;
    read_port_q    <= `ADDR_ELSE'b0;
end
else
begin
    read_pending_q <= read_pending_r;
    if (inport_arvalid_i && inport_arready_o)
    begin
        read_port_q <= read_port_r;
    end
end

wire read_accept_w       = (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);

assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_ELSE'd0);
assign outport_araddr_o  = inport_araddr_i;
assign outport_rready_o  = inport_rready_i;

assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_ELSE'd1);
assign outport_peripheral0_araddr_o  = inport_araddr_i;
assign outport_peripheral0_rready_o  = inport_rready_i;

// Write Port
reg [3:0]       write_pending_q;
reg [3:0]       write_pending_r;
reg [`ADDR_ELSE-1:0] write_port_q;
reg [`ADDR_ELSE-1:0] write_port_r;

wire write_accept_w      = (write_port_q == write_port_r && write_pending_q != 4'hF) || (write_pending_q == 4'h0);

always @ (posedge clk_i)
if (rst_i)
begin
    write_pending_q <= 4'h0;
    write_port_q    <= `ADDR_ELSE'b0;
end
else
begin
    write_pending_q <= write_pending_r;
    if (inport_awvalid_i && inport_awready_o && !write_accept_w)
    begin
        write_pending_q <= 4'hF;
        write_port_q <= `ADDR_ELSE'b0;
    end
end

wire write_accept_w      = (write_port_q == write_port_r && write_pending_q != 4'hF) || (write_pending_q == 4'h0);

always @ (posedge clk_i)
if (rst_i)
begin
    inport_awready_r = 4'h0;
    inport_wready_r  = 4'h0;
end
else
begin
    inport_awready_r = write_port_r;
    inport_wready_r  = write_port_r;
end

assign inport_awready_o = write_accept_w & ~write_pending_q & inport_awready_r;
assign inport_wready_o  = write_accept_w & ~write_pending_q & inport_wready_r;

// peripheral0 write
wire [3:0] peripheral0_mask = `0x80000000;
wire [3:0] peripheral0_addr_valid = inport_arvalid_i;
wire [3:0] peripheral0_addr_valid peripheral0_addr_valid_o;

wire [3:0] peripheral0_data_valid = inport_wvalid_i;
wire [3:0] peripheral0_data_valid peripheral0_data_valid_o;

wire [3:0] peripheral0_data peripheral0_data_o;

wire [3:0] peripheral0_response_valid = inport_bvalid_i;
wire [3:0] peripheral0_response_valid peripheral0_response_valid_o;

wire [3:0] peripheral0_response peripheral0_response_o;

// peripheral0 read
wire [3:0] peripheral0_addr_valid = outport_arvalid_o;
wire [3:0] peripheral0_addr_valid peripheral0_addr_valid_i;

wire [3:0] peripheral0_data_valid = outport_rvalid_o;
wire [3:0] peripheral0_data_valid peripheral0_data_valid_i;

wire [3:0] peripheral0_data = outport_rdata_o;
wire [3:0] peripheral0_data peripheral0_data_i;

wire [3:0] peripheral0_response_valid = outport_bvalid_o;
wire [3:0] peripheral0_response_valid peripheral0_response_valid_i;

wire [3:0] peripheral0_response = outport_bresp_o;
wire [3:0] peripheral0_response peripheral0_response_i;

// Default write
wire [3:0] default_mask = 0x00000000;
wire [3:0] default_addr_valid = inport_arvalid_i;
