output.rtl/precision_counter_axi.sv:
// Module parameters
parameter C_S_AXI_DATA_WIDTH = 32;
parameter C_S_AXI_ADDR_WIDTH = 8;

// Module ports
input axi_aclk;
input axi_aresetn;
output axi_awready;
output axi_wready;
output axi_bready;
output axi_bvalid;
output axi_rready;
output axi_rvalid;
output axi_ap_done;
output irq;

// Internal registers
reg [C_S_AXI_ADDR_WIDTH-1:0] slv_reg_ctl;
reg [C_S_AXI_DATA_WIDTH-1:0] slv_reg_v;
reg [C_S_AXI_DATA_WIDTH-1:0] slv_reg_t;
reg [C_S_AXI Data_WIDTH-1:0] slv_reg_irq_mask;
reg [C_S_AXI Data_WIDTH-1:0] slv_reg_irq_thresh;

// Module implementation
always_comb begin
  // AXI4-Lite write transaction
  if (axi_aclk) begin
    if (axi_aresetn) begin
      slv_reg_ctl = 0x00;
      slv_reg_v = 0x00;
      slv_reg_t = 0x00;
      slv_reg_irq_mask = 0x00;
      slv_reg_irq_thresh = 0x00;
    else begin
      if (slv_reg_ctl[0] == 1) begin
        slv_reg_v = (slv_reg_v + 1) & ((1 << C_S_AXI_DATA_WIDTH) - 1);
      end
      if (slv_reg_v == 0) begin
        axi_ap_done = 1;
        slv_reg_t = (slv_reg_t + 1) & ((1 << C_S_AXI_DATA_WIDTH) - 1);
      end
    end
  end

  // AXI4-Lite read transaction
  if (axi_aclk) begin
    if (axi_aresetn) begin
      slv_reg_ctl = 0x00;
      slv_reg_v = 0x00;
      slv_reg_t = 0x00;
      slv_reg_irq_mask = 0x00;
      slv_reg_irq_thresh = 0x00;
    else begin
      if (slv_reg_arvalid && slv_reg_araddr == 0x00) begin
        slv_reg_v = (slv_reg_v + 1) & ((1 << C_S_AXI_DATA_WIDTH) - 1);
      end
      if (slv_reg_v == 0) begin
        slv_reg_t = (slv_reg_t + 1) & ((1 << C_S_AXI_DATA_WIDTH) - 1);
      end
    end
  end
end

output.rtl/axis_image_border_gen.sv:
module axis_image_border_gen #(
    parameter IMG_WIDTH  = 336,
    parameter IMG_HEIGHT = 256,
    parameter BORDER_COLOR = 16'hFFFF,
    parameter DATA_MASK    = 16'h0000
)(
    input  wire            clk,
    input  wire            resetn,
    input  wire [15:0]     s_axis_tdata,
    input  wire            s_axis_tvalid,
    input  wire            s_axis_tlast,
    input  wire            s_axis_tuser,
    input  wire            m_axis_tready,
    output wire [15:0]     m_axis_tdata,
    output wire            m_axis_tvalid,
    output wire            m_axis_tlast,
    output wire            m_axis_tuser
)

    // State and Counter Registers
    reg [2:0] state, next_state;
    reg [15:0] x_count, y_count;
    reg border_valid;

    // Internal Control Signals
    wire is_top_row     = (y_count == 16'd0);
    wire is_bottom_row  = (y_count == IMG_HEIGHT + 1);
    wire is_left_border  = (x_count == 16'd0);
    wire is_right_border = (x_count == IMG_WIDTH + 1);
    wire is_border_pixel = (is_top_row || is_bottom_row || is_left_border || is_right_border);

    // FSM and Counter Logic
    always @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            state = ST_IDLE;
            next_state = ST_IDLE;
        else begin
            if (s_axis_tuser) begin
                state = ST_ROW_FIRST;
                next_state = ST_ROW_FIRST;
            end else begin
                state = state;
                next_state = state;
            end
        end
    end

    // State Transition Handling
    case (state)
        ST_IDLE: begin
            if (s_axis_tuser) begin
                state = ST_ROW_FIRST;
                next_state = ST_ROW_FIRST;
            end
        end
        ST_ROW_FIRST: begin
            if (s_axis_tlast) begin
                state = ST_ROW_LAST;
                next_state = ST_ROW_LAST;
            end else begin
                x_count = 16'd0;
                y_count = 16'd0;
                state = ST_PROCESS_ROW;
                next_state = ST_PROCESS_ROW;
            end
        end
        ST_PROCESS_ROW: begin
            if (s_axis_tlast) begin
                state = ST_ROW_LAST;
                next_state = ST_ROW_LAST;
            end else begin
                x_count = x_count + 1;
                y_count = y_count + 1;
                state = ST_PROCESS_ROW;
                next_state = ST_PROCESS_ROW;
            end
        end
        ST_ROW_LAST: begin
            if (s_axis_tuser) begin
                state = ST_ROW_FIRST;
                next_state = ST_ROW_FIRST;
            end
        end
        ST_BORDER_ROW: begin
            if (s_axis_tlast) begin
                state = ST_ROW_LAST;
                next_state = ST_ROW_LAST;
            end
        end
    endcase

    // Border Generation Logic
    always @(posedge clk) begin
        if (!resetn) begin
            x_count = 16'd0;
            y_count = 16'd0;
            border_valid = 0;
        end else begin
            if (is_border_pixel) begin
                border_valid = 1;
            else begin
                border_valid = 0;
            end
        end
    end

    // AXI Output Signals
    wire [15:0] m_axis_tdata_next;
    wire [15:0] m_axis_tdata_next_valid;

    // Processing Pixel Data
    always @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            m_axis_tvalid = 0;
            m_axis_tready = 0;
            m_axis_tlast = 0;
        end else begin
            if (border_valid) begin
                m_axis_tdata_next = (BORDER_COLOR & DATA_MASK);
                m_axis_tvalid = 1;
            else begin
                m_axis_tdata_next = (s_axis_tdata & DATA_MASK);
                m_axis_tvalid = 1;
            end
        end
    end

    // Updating AXI Output
    always @(posedge clk) begin
        if (m_axis_tvalid) begin
            m_axis_tdata_next_valid = 1;
        end
    end

    // Finalizing Output
    always begin
        if (m_axis_tready) begin
            m_axis_tdata = m_axis_tdata_next;
            m_axis_tvalid = 0;
            m_axis_tlast = 0;
        end
    end

    // State Machine Outputs
    wire [2:0] m_axis_tuser_next;

    // Final State Handling
    always begin
        if (state == ST_ROW_LAST) begin
            m_axis_tuser_next = 1;
        else begin
            m_axis_tuser_next = 0;
        end
    end

    // Assign Outputs
    m_axis_tuser = m_axis_tuser_next;
    m_axis_tready = m_axis_tready;
    m_axis_tlast = m_axis_tlast;
    m_axis_tdata = m_axis_tdata_next;
    m_axis_tvalid = m_axis_tvalid;
    m_axis_tdata_next = m_axis_tdata;
    m_axis_tdata_next_valid = m_axis_tvalid;

endmodule

output.rtl/axis_joiner.sv:
module axis_joiner(
    input clock,
    input rst,
    input [7:0] s_axis_tdata_1,
    input [1:0] s_axis_tvalid_1,
    output [7:0] s_axis_tready_1,
    input [7:0] s_axis_tlast_1,
    input [7:0] s_axis_tdata_2,
    input [1:0] s_axis_tvalid_2,
    output [1:0] s_axis_tready_2,
    input [7:0] s_axis_tlast_2,
    input [7:0] s_axis_tdata_3,
    input [1:0] s_axis_tvalid_3,
    output [1:0] s_axis_tready_3,
    output [7:0] m_axis_tdata,
    output [1:0] m_axis_tvalid,
    output [1:0] m_axis_tready,
    output [7:0] m_axis_tlast,
    output [1:0] m_axis_tuser
);

    // State variables
    reg state = IDLE;
    reg [2:0] buffer_reg1 = 0;
    reg [2:0] buffer_reg2 = 0;
    reg [2:0] buffer_reg3 = 0;
    reg [7:0] temp_reg1 = 0;
    reg [7:0] temp_reg2 = 0;
    reg [7:0] temp_reg3 = 0;
    reg [7:0] current_data = 0;

    // FSM process
    always_ff @* begin
        case (state)
            IDLE:
                if (s_axis_tvalid_1) begin
                    state = STATE_1;
                    current_data = s_axis_tdata_1;
                    temp_reg1 = 0;
                    temp_reg2 = 0;
                    temp_reg3 = 0;
                end else if (s_axis_tvalid_2) begin
                    state = STATE_2;
                    current_data = s_axis_tdata_2;
                    temp_reg1 = 0;
                    temp_reg2 = 0;
                    temp_reg3 = 0;
                end else if (s_axis_tvalid_3) begin
                    state = STATE_3;
                    current_data = s_axis_tdata_3;
                    temp_reg1 = 0;
                    temp_reg2 = 0;
                    temp_reg3 = 0;
                end else begin
                    state = IDLE;
                end
            STATE_1:
                if (s_axis_tlast_1) begin
                    state = IDLE;
                    m_axis_tvalid = 1;
                    m_axis_tready = 1;
                    m_axis_tdata = current_data;
                    m_axis_tuser = 0x1;
                end else begin
                    temp_reg1 = current_data;
                    temp_reg2 = 0;
                    temp_reg3 = 0;
                end
            STATE_2:
                if (s_axis_tlast_2) begin
                    state = IDLE;
                    m_axis_tvalid = 1;
                    m_axis_tready = 1;
                    m_axis_tdata = current_data;
                    m_axis_tuser = 0x2;
                end else begin
                    temp_reg2 = current_data;
                    temp_reg1 = 0;
                    temp_reg3 = 0;
                end
            STATE_3:
                if (s_axis_tlast_3) begin
                    state = IDLE;
                    m_axis_tvalid = 1;
                    m_axis_tready = 1;
                    m_axis_tdata = current_data;
                    m_axis_tuser = 0x3;
                end else begin
                    temp_reg3 = current_data;
                    temp_reg1 = 0;
                    temp_reg2 = 0;
                end
            default:
                state = IDLE;
        endcase
    end

    // Assign outputs
    m_axis_tdata = temp_reg1;
    m_axis_tvalid = 0;
    m_axis_tready = 0;
    m_axis_tlast = 0;
    m_axis_tuser = 0;

    // Reset handling
    always rstbegin
        state = IDLE;
        m_axis_tvalid = 0;
        m_axis_tready = 0;
        m_axis_tlast = 0;
        temp_reg1 = 0;
        temp_reg2 = 0;
        temp_reg3 = 0;
    end
    always rstend

endmodule

output.rtl/axis_mux.sv:
module axis_mux #(
  parameter integer C_AXIS_DATA_WIDTH = 32,
  parameter integer C_AXIS_TUSER_WIDTH = 4,
  parameter integer C_AXIS_TID_WIDTH   = 2,
  parameter integer C_AXIS_TDEST_WIDTH = 2,
  parameter integer NUM_INPUTS         = 4
)(
  input  wire                                   aclk,
  input  wire                                   aresetn,
  input  wire [$clog2(NUM_INPUTS)-1:0]          sel,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tvalid,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tready,
  input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH-1:0]   s_axis_tdata,
  input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH/8-1:0] s_axis_tkeep,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tlast,
  input  wire [NUM_INPUTS*C_AXIS_TID_WIDTH-1:0] s_axis_tid,
  input  wire [NUM_INPUTS*C_AXIS_TDEST_WIDTH-1:0] s_axis_tdest,
  input  wire [NUM_INPUTS*C_AXIS_TUSER_WIDTH-1:0] s_axis_tuser,
  output wire                                   m_axis_tvalid,
  output wire [C_AXIS_DATA_WIDTH-1:0]           m_axis_tdata,
  output wire [C_AXIS_DATA_WIDTH/8-1:0]         m_axis_tkeep,
  output wire                                   m_axis_tlast,
  output wire [C_AXIS_TID_WIDTH-1:0]            m_axis_tid,
  output wire [C_AXIS_TDEST_WIDTH-1:0]          m_axis_tdest,
  output wire [C_AXIS_TUSER_WIDTH-1:0]          m_axis_tuser,
  output wire                                   m_axis_tready
);

// Register to hold the selected input index
integer sel_reg = 0;

// Select input based on sel
if (sel < 0 || sel >= NUM_INPUTS) begin
  // No valid input selected
  m_axis_tvalid = 0;
  m_axis_tready = 0;
  m_axis_tdata = 0;
  m_axis_tkeep = 0;
  m_axis_tlast = 0;
  m_axis_tid = 0;
  m_axis_tdest = 0;
  m_axis_tuser = 0;
  return;
end

if (s_axis_tvalid[sel] == 1) begin
  // Selected input is valid
  m_axis_tvalid = 1;
  m_axis_tready = 1;
  m_axis_tdata = s_axis_tdata[sel * C_AXIS_DATA_WIDTH: (sel * C_AXIS_DATA_WIDTH) + C_AXIS_DATA_WIDTH - 1];
  m_axis_tkeep = s_axis_tkeep[sel * C_AXIS_DATA_WIDTH/8: (sel * C_AXIS_DATA_WIDTH/8) + C_AXIS_DATA_WIDTH/8 - 1];
  m_axis_tlast = s_axis_tlast[sel];
  m_axis_tid = s_axis_tid[sel * C_AXIS_TID_WIDTH: (sel * C_AXIS_TID_WIDTH) + C_AXIS_TID_WIDTH - 1];
  m_axis_tdest = s_axis_tdest[sel * C_AXIS_TDEST_WIDTH: (sel * C_AXIS_TDEST_WIDTH) + C_AXIS_TDEST_WIDTH - 1];
  m_axis_tuser = s_axis_tuser[sel * C_AXIS_TUSER_WIDTH: (sel * C_AXIS_TUSER_WIDTH) + C_AXIS_TUSER_WIDTH - 1];
end

// If no input is valid, set all outputs to 0
if (m_axis_tvalid == 0) begin
  m_axis_tready = 0;
  m_axis_tdata = 0;
  m_axis_tkeep = 0;
  m_axis_tlast = 0;
  m_axis_tid = 0;
  m_axis_tdest = 0;
  m_axis_tuser = 0;
end

endmodule

