output.rtl/barrel_shifter.sv:
module barrel_shifter(input [(parameter data_width - 1):0] data_in, input [(parameter shift_bits_width - 1):0] shift_bits, input rotate_left_right, input left_right, output [(parameter data_width - 1):0] data_out);
  parameter data_width = 16;
  parameter shift_bits_width = 4;
  integer shift_amount;
  integer rotate_amount;

  assign shift_amount = shift_bits;
  assign rotate_amount = shift_bits;

  case ({rotate_left_right, left_right})
    // Rotate left
    1, 1:
      data_out = (data_in << rotate_amount) | (data_in >> (data_width - rotate_amount));
      break;
    // Rotate right
    0, 1:
      data_out = (data_in >> rotate_amount) | (data_in << (data_width - rotate_amount));
      break;
    // Shift left
    1, 0:
      data_out = data_in << rotate_amount;
      break;
    // Shift right
    0, 0:
      data_out = data_in >> rotate_amount;
      break;
  endcase
endmodule

input.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,      // Change data_width to 16
    parameter shift_bits_width = 4  // Update shift_bits_width to handle shifts for 16-bit width
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input left_right,               // 1: left shift, 0: right shift
    input rotate_left_right,        // 1: rotate, 0: shift
    input arithmetic_shift,         // 1: arithmetic shift, 0: logical shift
    output reg [data_width-1:0] data_out
);

always @(*) begin
    if (rotate_left_right) begin
        // Rotation logic
        if (left_right)
            data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits)); // Rotate left
        else
            data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits)); // Rotate right
    end else begin
        // Shift logic
        if (left_right)
            data_out = data_in << shift_bits;  // Left shift
        else if (arithmetic_shift)
            // Arithmetic right shift: explicitly sign-extend data_in to ensure the MSB (sign bit) is preserved
            data_out = $signed(data_in) >>> shift_bits;
        else
            data_out = data_in >> shift_bits;  // Logical right shift
    end
end

endmodule

output.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,
    parameter shift_bits_width = 4,
    parameter mode_width = 3
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input mode,
    input [data_width-1:0] mask,
    input left_right,
    input rotate_left_right,
    input arithmetic_shift,
    output reg [data_width-1:0] data_out,
    output reg error
);

    // Internal variables
    reg [data_width-1:0] shifted_data;
    reg [data_width-1:0] result;

    always @(*) begin
        case (mode)
            000: begin
                if (left_right)
                    shifted_data = data_in << shift_bits;
                else
                    shifted_data = data_in >> shift_bits;
                data_out = shifted_data;
            endbreak

            001: begin
                if (left_right)
                    shifted_data = data_in << shift_bits;
                else
                    shifted_data = $signed(data_in) >>> shift_bits;
                data_out = shifted_data;
            endbreak

            010: begin
                if (left_right)
                    shifted_data = (data_in << shift_bits) | (data_in >> (data_width - shift_bits));
                else
                    shifted_data = (data_in >> shift_bits) | (data_in << (data_width - shift_bits));
                data_out = shifted_data;
            endbreak

            011: begin
                if (left_right)
                    shifted_data = (data_in << shift_bits);
                else
                    shifted_data = (data_in >> shift_bits);
                result = shifted_data & mask;
                data_out = result;
            endbreak

            100: begin
                if (left_right)
                    shifted_data = (data_in << shift_bits);
                else
                    shifted_data = (data_in >> shift_bits);
                result = shifted_data ^ mask;
                data_out = result;
            endbreak

            default:
                error = 1;
                data_out = 0;
                break;
        endcase
    end
end

endmodule

input.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,     
    parameter shift_bits_width = 4  
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input [2:0] mode,               
    input left_right,              
    input [data_width-1:0] mask,   
    output reg [data_width-1:0] data_out,
    output reg error                
);

always @(*) begin
    error = 0;  
    case (mode)
        3'b000: begin
            if (left_right)
                data_out = data_in << shift_bits;  
            else
                data_out = data_in >> shift_bits; 
        end
        3'b001: begin
            if (left_right) 
                data_out = data_in << shift_bits; 
            else
                data_out = $signed(data_in) >>> shift_bits; 
        end
        3'b010: begin
            if (left_right)
                data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits)); 
            else
                data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits));  
        end
        3'b011: begin
            if (left_right)
                data_out = (data_in << shift_bits) & mask;  
            else
                data_out = (data_in >> shift_bits) & mask; 
        end
        3'b100: begin
            if (left_right)
                data_out = (data_in << shift_bits) ^ mask; 
            else
                data_out = (data_in >> shift_bits) ^ mask; 
        end
        default: begin
            data_out = {data_width{1'b0}}; 
            error = 1; 
        end
    endcase
end

endmodule

output.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,
    parameter shift_bits_width = 4
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input [2:0] mode,
    input enable,
    input enable_parity,
    input left_right,
    input [data_width-1:0] mask,
    output reg [data_width-1:0] data_out,
    output reg error
);

always @(*) begin
    if (enable == 0) begin
        data_out = 0;
        error = 0;
        return;
    end

    case (mode)
        3'b000: begin
            if (left_right)
                data_out = data_in << shift_bits;
            else
                data_out = data_in >> shift_bits;
        end
        3'b001: begin
            if (left_right)
                data_out = data_in << shift_bits;
            else
                data_out = $signed(data_in) >>> shift_bits;
        end
        3'b010: begin
            if (left_right)
                data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits));
            else
                data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits));
        end
        3'b011: begin
            if (left_right)
                data_out = (data_in << shift_bits) & mask;
            else
                data_out = (data_in >> shift_bits) & mask;
        end
        3'b100: begin
            if (left_right) begin
                data_out = data_in + shift_bits;
            else begin
                data_out = data_in - shift_bits;
            end
            if (data_out < 0) data_out += data_width;
        end
        3'b101: begin
            if (data_in == 0) begin
                data_out = 0;
                error = 0;
            else begin
                integer pos = -1;
                for (integer i = data_width-1; i >= 0; i--) begin
                    if ((data_in >> i) & 1) begin
                        pos = i;
                        break;
                    end
                end
                data_out = (data_in >> pos) << (data_width - pos - 1);
            end
        end
        3'b110: begin
            if (left_right) begin
                data_out = (data_in + shift_bits) % data_width;
            else begin
                data_out = (data_in - shift_bits) % data_width;
            end
        end
        default: begin
            data_out = 0;
            error = 1;
        end
    endcase
    if (enable_parity == 1) begin
        parity_out = data_out;
    else begin
