`timescale 1ns / 1ps
module bcd_to_excess_3(
    input [3:0] bcd,          // 4-bit BCD input
    output reg [3:0] excess3, // 4-bit Excess-3 output
    output reg error          // Error flag to indicate invalid input
);

// The always block triggers on any change to the BCD input.
always @(bcd)
begin
    error = 1'b0; 
    case(bcd)
        4'b0000: excess3 = 4'b0011;  
        4'b0001: excess3 = 4'b0100;  
        4'b0010: excess3 = 4'b0101;  
        4'b0011: excess3 = 4'b0110;  
        4'b0100: excess3 = 4'b0111;  
        4'b0101: excess3 = 4'b1000;  
        4'b0110: excess3 = 4'b1001;  
        4'b0111: excess3 = 4'b1010;  
        4'b1000: excess3 = 4'b1011;  
        4'b1001: excess3 = 4'b1100;  
        default: begin
            excess3 = 4'b0000;   // Set output to 0 on invalid input.
            error = 1'b1;        // Set error flag to 1 to indicate an invalid input was received.
        end
    endcase
end
endmodule

output.rtl/bcd_to_excess_3.sv:
module bcd_to_excess_3(
    input clock,
    input rst,
    input enable,
    input [3:0] bcd,
    output reg [3:0] excess3,
    output reg error,
    output reg parity,
    output reg [1:0] error_code
);

    // State machine to handle synchronous reset and enable states
    statecase state
        // Reset state
        when (rst == 1'b1) begin
            excess3 = 4'b0000;
            error = 0'b0;
            parity = 0'b0;
            error_code = 2'b00;
            state = '0; // Default state
        end

        // Active state
        when (enable == 1'b1) begin
            // Validate BCD input
            if (bcd >= 4'b0000 && bcd <= 4'b1001) begin
                // Calculate Excess-3 code
                excess3 = compute_excess3(bcd);
                // Calculate parity
                parity = bcd[3] ^ bcd[2] ^ bcd[1] ^ bcd[0];
                // No error
                error_code = 2'b00;
            else begin
                // Invalid input
                excess3 = 4'b0000;
                error = 1'b1;
                parity = 0'b0;
                error_code = 2'b01;
            end
        end

        default: state = '0;
    endcase

    // Function to compute Excess-3 code
    function [3:0] compute_excess3(input [3:0] bcd) begin
        reg [3:0] sum;
        sum = bcd + 3;
        return sum;
    endfunction
endmodule

