    parameter PARKING_FEE_VALUE = 50,
    parameter MAX_DAILY_FEE = 500,
    parameter WARNING_LIMIT = 12 * 3600, // 12 hours in seconds
    parameter OVERSTAY_LIMIT = 24 * 3600 // 24 hours in seconds
)(
    input wire clk,
