module continuous_adder (
    input logic         clk,         // Clock signal
    input logic         reset,       // Reset signal, Active high and Synchronous
    input logic [{DATA_WIDTH}-1:0]   data_in,     // Input data stream (DATA_WIDTH bit)
    input logic         data_valid,  // Input data valid signal
    output logic [{DATA_WIDTH}-1:0]  sum_out,     // Output the accumulated sum
    output logic        sum_ready    // Signal to indicate sum is output and accumulator is reset
);

    parameter logic parameter DATA_WIDTH = 32;
    parameter logic parameter THRESHOLD_VALUE = 100;
    parameter logic parameter SIGNED_INPUTS = 1;

    logic [{DATA_WIDTH}-1:0] sum_accum;          // Internal accumulator to store the running sum

    // Sequential logic for sum accumulation
    always_ff @(posedge clk) begin
        if (reset) begin
            // On reset, clear the accumulator, reset sum_out and sum_ready
            sum_accum         <= 8'd0;
            sum_ready         <= 1'b0;
        end
        else begin
            if (data_valid) begin
                // Add input data to the accumulator
                sum_accum     <= sum_accum + data_in;

                // Check if the accumulated sum is >= THRESHOLD_VALUE or <= -THRESHOLD_VALUE
                if (SIGNED_INPUTS) begin
                    if (sum_accum >= THRESHOLD_VALUE || sum_accum <= -THRESHOLD_VALUE) begin
                        // Output the current sum and reset the accumulator
                        sum_out   <= sum_accum;
                        sum_ready <= 1'b1;
                        sum_accum <= ({DATA_WIDTH}-1:0) 0;
                    end
                    else begin
                        // Continue accumulating, but no output until the sum reaches 100
                        sum_ready <= 1'b0;
                    end
                end
                else begin
                    if (sum_accum + data_in >= THRESHOLD_VALUE) begin
                        // Output the current sum and reset the accumulator
                        sum_out   <= sum_accum + data_in;
                        sum_ready <= 1'b1;
                        sum_accum <= 8'd0;
                    end
                    else begin
                        // Continue accumulating, but no output yet
                        sum_ready <= 1'b0;
                    end
                end
            end
        end
    end

    // Constraint check for signed inputs
    if (!SIGNED_INPUTS && THRESHOLD_VALUE >= (1 << DATA_WIDTH)) begin
        $error "THRESHOLD_VALUE must be less than 2^DATA_WIDTH when SIGNED_INPUTS is 0";
    end
    if (SIGNED_INPUTS && THRESHOLD_VALUE >= (1 << (DATA_WIDTH-1))) begin
        $error "THRESHOLD_VALUE must be less than 2^(DATA_WIDTH-1) when SIGNED_INPUTS is 1";
    end
endmodule

module continuous_adder #(
    parameter DATA_WIDTH = 32,
    parameter THRESHOLD_VALUE_1 = 50,
    parameter THRESHOLD_VALUE_2 = 100,
    parameter SIGNED_INPUTS = 1,
    parameter ACCUM_MODE = 0,
    parameter WEIGHT = 1
) (
    input logic clock, 
    input logic reset, 
    input logic data_valid,
    input logic signed [DATA_WIDTH-1:0] data_in,
    input logic weight [DATA_WIDTH-1:0] weighted_input,
    output logic signed [DATA_WIDTH-1:0] sum_out,
    output logic signed [DATA_WIDTH-1:0] avg_out,
    output logic sum_ready,
    output logic threshold_1,
    output logic threshold_2
);

    logic signed [DATA_WIDTH-1:0] sum_accum;
    logic signed [DATA_WIDTH-1:0] sum_accum_prev;
    logic [DATA_WIDTH-1:0] internal_weighted_input;
    logic [DATA_WIDTH-1:0] internal_weighted_input_prev;
    logic window_count;
    logic [DATA_WIDTH-1:0] internal_sum;
    logic [DATA_WIDTH-1:0] internal_sum_prev;
    logic signed [DATA_WIDTH-1:0] threshold_1_comb;
    logic signed [DATA_WIDTH-1:0] threshold_2_comb;
    logic signed [DATA_WIDTH-1:0] sum Ready_comb;
    logic signed [DATA_WIDTH-1:0] sum_comb;

    // Sequential logic for sum accumulation
    always_ff @(posedge clock) begin
        if (reset) begin
            sum_accum <= {DATA_WIDTH{1'b0}};
            sum_ready <= 1'b0;
            sum_out <= {DATA_WIDTH{1'b0}};
            sum_comb <= {DATA_WIDTH{1'b0}};
        end
        else begin
            if (data_valid) begin
                if (ACCUM_MODE == 0) begin
                    if (sum_ready) begin
                        sum_comb <= sum_accum;
                        sum_out <= sum_comb;
                        sum_ready <= 1'b0;
                    end
                    sum_accum <= sum_accum + data_in;
                    sum_comb <= sum_accum;
                end else begin
                    if (ACCUM_MODE == 1) begin
                        if (window_count >= window_size) begin
                            sum_comb <= sum_accum;
                            avg_out <= sum_comb;
                            avg_out <= sum_comb;
                            sum_ready <= 1'b1;
                            sum_out <= sum_comb;
                            sum_accum <= {DATA_WIDTH{1'b0}};
                            window_count <= 0;
                        end
                        sum_accum <= sum_accum + data_in * WEIGHT;
                        internal_weighted_input <= data_in * WEIGHT;
                        internal_sum <= internal_sum_prev + internal_weighted_input;
                        internal_sum_prev <= internal_sum;
                        sum_comb <= internal_sum;
                    end
                end
            end
        end
    end

    // Threshold detection logic
    always_comb begin
        threshold_1_comb <= (sum_comb >= THRESHOLD_VALUE_1) || (sum_comb <= -THRESHOLD_VALUE_1);
        threshold_2_comb <= (sum_comb >= THRESHOLD_VALUE_2) || (sum_comb <= -THRESHOLD_VALUE_2);
    end

    // Output signals
    sum_out <= sum_comb;
    threshold_1 <= threshold_1_comb;
    threshold_2 <= threshold_2_comb;
    sum_ready <= sum_ready_comb;
endmodule

