        door_open <= 1;
    end else if(present_state == DOOR_OPEN) begin
        door_open <= 1;
    end else begin
        door_open <= 0;
    end
end


always @(posedge clk or posedge reset) begin
    if(reset) begin
        door_open_counter <= DOOR_OPEN_CYCLES;
    end else if( present_state == DOOR_OPEN) begin
        if(door_open_counter > 0 ) begin
