module divider #
(
    parameter WIDTH = 32
)
(
    input  wire                  clk,
    input  wire                  rst_n,
    input  wire                  start,
    input  wire [WIDTH-1 : 0]    dividend,
    input  wire [WIDTH-1 : 0]    divisor,
    output wire [WIDTH-1 : 0]    quotient,
    output wire [WIDTH-1 : 0]    remainder,
    output wire                  valid
);

    localparam AW = WIDTH + 1;
    localparam IDLE = 2'b00;
    localparam BUSY = 2'b01;
    localparam DONE = 2'b10;

    reg [1:0] state_reg, state_next;

    reg [AW+WIDTH-1 : 0] aq_reg, aq_next;
    reg [AW-1 : 0]       m_reg, m_next;
    reg [AW-1 : 0]       n_reg, n_next;
    reg [WIDTH-1:0]      quotient_reg, quotient_next;
    reg [WIDTH-1:0]      remainder_reg, remainder_next;
    reg valid_reg, valid_next;

    if (start) begin
        m_reg = dividend;
        aq_reg = dividend;
        state_next = BUSY;
    end

    always @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            state_reg = IDLE;
            aq_reg = 0;
            m_reg = 0;
            n_reg = WIDTH;
            quotient_reg = 0;
            remainder_reg = 0;
            valid_reg = 0;
        end else if (state_reg == IDLE) begin
            if (start) begin
                state_reg = BUSY;
                aq_next = aq_reg;
                m_next = m_reg;
            end
        end else if (state_reg == BUSY) begin
            if (n_reg == 0) begin
                state_next = DONE;
            end else begin
                n_next = n_reg - 1;
                aq_next = (aq_reg << 1) | (valid ? (n_reg % 2) ? 1 : 0 : 0);

                if (valid) begin
                    if (valid) begin
                        if (valid) begin
                            m_next = m_reg;
                        end else begin
                            m_next = m_reg ^ (1 << (WIDTH-1));
                        end
                    end
                end else begin
                    m_next = m_reg;
                end

                if (valid) begin
                    if (valid) begin
                        if (valid) begin
                            quotient_next = quotient_reg | (1 << (WIDTH-1 - n_reg));
                        end else begin
                            quotient_next = quotient_reg;
                        end
                    end else begin
                        quotient_next = quotient_reg;
                    end
                else begin
                    quotient_next = quotient_reg;
                end

                if (valid) begin
                    if (valid) begin
                        if (valid) begin
                            remainder_next = remainder_reg + m_reg;
                        end else begin
                            remainder_next = remainder_reg - m_reg;
                        end
                    end else begin
                        remainder_next = remainder_reg;
                    end
                else begin
                    remainder_next = remainder_reg;
                end
            end
        end else if (state_reg == DONE) begin
            valid_next = 1;
        end
    end

    assign aq_next = aq_next;
    assign m_next = m_next;
    assign n_next = n_next;
    assign quotient_next = quotient_next;
    assign remainder_next = remainder_next;
    assign valid_next = valid_next;

    always @* valid begin
        quotient_reg = quotient_reg;
        remainder_reg = remainder_reg;
        valid_reg = valid;
    end

    // Final adjustment
    if (valid) begin
        if (remainder_reg[WIDTH-1] == 1) begin
            remainder_reg = remainder_reg + m_reg;
        end
    end

    // Update state
    state_reg = state_next;
endmodule

module divider (
    input  logic         clk,
    input  logic         rst_n,
    input  logic         start,
    input  logic [17:0]  dividend,
    input  logic [17:0]  divisor,
    output logic [17:0]  dv_out,
    output logic         valid
);

    logic [17:0] D_0, N_0;
    logic [17:0] D, D2, D4, D6, D8, D10, D12, D14, D16, D18, D20;
    logic [17:0] N, N2, N4, N6, N8, N10, N12, N14, N16, N18, N20, N21;
    logic [47:0] D1, N1, D3, N3, D5, N5, D7, N7, D9, N9, D11, N11, D13, N13, D15, N15, D17, N17, D19, N19;

    //Pipeline stage flags
    logic st1, st2, st3, st4, st5, st6, st7, st8, st9, st10, st11, st12;

    // Gold-Schmidt factors
    logic [17:0] TWO = 18'b000000010_000000000,
                  ZERO = 18'b000000000_000000000;

    // Pre-scaling module
    wire [17:0] pre_dividend, pre_divisor;
    pre_scaler(divisor, dividend, pre_divisor, pre_dividend);

    // Pipeline stages
    always logic valid = 1;
    always logic st1 = 1;
    always logic st2 = 1;
    always logic st3 = 1;
    always logic st4 = 1;
    always logic st5 = 1;
    always logic st6 = 1;
    always logic st7 = 1;
    always logic st8 = 1;
    always logic st9 = 1;
    always logic st10 = 1;
    always logic st11 = 1;
    always logic st12 = 1;

    // Iterations
    always logic valid = 1;
    for (int i = 0; i < 10; i++) {
        // Step 1: Generate multiplication factor
        F[i] = 2 - D_prev;

        // Step 2: Multiply dividend and divisor by F[i]
        D_current = D_prev * F[i];
        N_current = N_prev * F[i];

        // Step 3: Update intermediate values
        D_next = D_current;
        N_next = N_current;

        // Step 4: Update factors
        F_next = F[i] * 2 - D_current;
    }

    // After iterations, output the result
    dv_out = N_final;
    valid = 1;

    // Final valid assertion
    valid = 1;

endmodule

