//////////////////////////////////////////////
// Top-Level Gold-Schmidt Division Module
//////////////////////////////////////////////
module divider (
    input  logic         clk,
    input  logic         rst_n,
    input  logic         start,
    input  logic [17:0]  dividend,  // unsigned
    input  logic [17:0]  divisor,   // unsigned
    output logic [17:0]  dv_out,
    output logic         valid
);

    //////////////////////////////////////////////
    // Local parameters
    //////////////////////////////////////////////
    localparam logic [17:0] TWO  = 18'b000000010_000000000;  // "2.0" in Q9.9
    localparam logic [17:0] ZERO = 18'b000000000_000000000;  // "0.0" in Q9.9

    //////////////////////////////////////////////
    // Internal signals
    //////////////////////////////////////////////
    logic [17:0] D_0, N_0;
    logic [17:0] D, D2, D4, D6, D8, D10, D12, D14, D16, D18, D20;
    logic [17:0] N, N2, N4, N6, N8, N10, N12, N14, N16, N18, N20, N21;
    logic [17:0] F, F1, F2, F3, F4, F5, F6, F7, F8, F9;
    logic [47:0] D1, N1, D3, N3, D5, N5, D7, N7, D9, N9, D11, N11, D13, N13, D15, N15, D17, N17, D19, N19;

    // Pipeline stage flags
    logic st1, st2, st3, st4, st5, st6, st7, st8, st9, st10, st11, st12;

    //////////////////////////////////////////////
    // Pre-registers for dividend/divisor
    //////////////////////////////////////////////
    reg18 reg_dividend_pre(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(dividend),
        .data_out(N_0)
    );

    reg18 reg_divisor_pre(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(divisor),
        .data_out(D_0)
    );

    // Pipeline control for "start"
    dff1 ff0(
        .clk   (clk),
        .reset (~rst_n),
        .d     (start),
        .q     (st1)
    );

    //////////////////////////////////////////////
    // Prescaling: only for magnitude < 1
    //////////////////////////////////////////////
    logic [17:0] prescaled_divisor, prescaled_dividend;
    pre_scaler prescaler_inst(
        .a(D_0),
        .c(N_0),
        .b(prescaled_divisor),
        .d(prescaled_dividend)
    );

    //////////////////////////////////////////////
    // Register the prescaled divisor & dividend
    //////////////////////////////////////////////
    reg18 reg_divisor_stage1(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(prescaled_divisor),
        .data_out(D)
    );

    reg18 reg_dividend_stage1(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(prescaled_dividend),
        .data_out(N)
    );

    dff1 ff1(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st1),
        .q     (st2)
    );

    //////////////////////////////////////////////
    // Stage 1: Compute F = (2 - D), multiply, register
    //////////////////////////////////////////////
    always_comb begin
        // Because we're unsigned and D < 1.0, we do F = 2 - D
        F = TWO - D;
    end

    assign D1 = F * D;
    assign N1 = F * N;

    reg18 reg_divisor_stage2(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D1[26:9]),     // Keep 18 bits
        .data_out(D2)
    );

    reg18 reg_dividend_stage2(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N1[26:9]),
        .data_out(N2)
    );

    dff1 ff2(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st2),
        .q     (st3)
    );

    //////////////////////////////////////////////
    // Stage 2: F1 = 2 - D2, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F1 = TWO - D2;
    end

    assign D3 = F1 * D2;
    assign N3 = F1 * N2;

    reg18 reg_divisor_stage3(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D3[26:9]),
        .data_out(D4)
    );

    reg18 reg_dividend_stage3(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N3[26:9]),
        .data_out(N4)
    );

    dff1 ff3(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st3),
        .q     (st4)
    );

    //////////////////////////////////////////////
    // Stage 3: F2 = 2 - D4, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F2 = TWO - D4;
    end

    assign D5 = F2 * D4;
    assign N5 = F2 * N4;

    reg18 reg_divisor_stage4(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D5[26:9]),
        .data_out(D6)
    );

    reg18 reg_dividend_stage4(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N5[26:9]),
        .data_out(N6)
    );

    dff1 ff4(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st4),
        .q     (st5)
    );

    //////////////////////////////////////////////
    // Stage 4: F3 = 2 - D6, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F3 = TWO - D6;
    end

    assign D7 = F3 * D6;
    assign N7 = F3 * N6;

    reg18 reg_divisor_stage5(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D7[26:9]),
        .data_out(D8)
    );

    reg18 reg_dividend_stage5(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N7[26:9]),
        .data_out(N8)
    );

    dff1 ff6(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st5),
        .q     (st6)
    );

    //////////////////////////////////////////////
    // Stage 5: F4 = 2 - D8, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F4 = TWO - D8;
    end

    assign D9 = F4 * D8;
    assign N9 = F4 * N8;

    reg18 reg_divisor_stage6(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D9[26:9]),
        .data_out(D10)
    );
    reg18 reg_dividend_stage6(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N9[26:9]),
        .data_out(N10)
    );

    dff1 ff8(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st6),
        .q     (st7)
    );

    //////////////////////////////////////////////
    // Stage 6: F5 = 2 - D10, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F5 = TWO - D10;
    end

    assign D11 = F5 * D10;
    assign N11 = F5 * N10;

    reg18 reg_divisor_stage7(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D11[26:9]),
        .data_out(D12)
    );
    reg18 reg_dividend_stage7(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N11[26:9]),
        .data_out(N12)
    );

    dff1 ff9(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st7),
        .q     (st8)
    );


    //////////////////////////////////////////////
    // Stage 7: F6 = 2 - D12, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F6 = TWO - D12;
    end

    assign D13 = F6 * D12;
    assign N13 = F6 * N12;

    reg18 reg_divisor_stage8(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D13[26:9]),
        .data_out(D14)
    );
    reg18 reg_dividend_stage8(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N13[26:9]),
        .data_out(N14)
    );

    dff1 ff10(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st8),
        .q     (st9)
    );


    //////////////////////////////////////////////
    // Stage 8: F7 = 2 - D14, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F7 = TWO - D14;
    end

    assign D15 = F7 * D14;
    assign N15 = F7 * N14;

    reg18 reg_divisor_stage9(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D15[26:9]),
        .data_out(D16)
    );
    reg18 reg_dividend_stage9(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N15[26:9]),
        .data_out(N16)
    );

    dff1 ff11(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st9),
        .q     (st10)
    );

    //////////////////////////////////////////////
    // Stage 9: F8 = 2 - D16, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F8 = TWO - D16;
    end

    assign D17 = F8 * D16;
    assign N17 = F8 * N16;

    reg18 reg_divisor_stage10(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D17[26:9]),
        .data_out(D18)
    );
    reg18 reg_dividend_stage10(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N17[26:9]),
        .data_out(N18)
    );

    dff1 ff12(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st10),
        .q     (st11)
    );

    //////////////////////////////////////////////
    // Stage 10: F9 = 2 - D18, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F9 = TWO - D18;
    end

    assign D19 = F9 * D18;
    assign N19 = F9 * N18;

    reg18 reg_divisor_stage11(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D19[26:9]),
        .data_out(D20)
    );
    reg18 reg_dividend_stage11(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N19[26:9]),
        .data_out(N20)
    );

    dff1 ff13(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st11),
        .q     (st12)
    );

    always_comb begin
        N21 = N20;
    end

    // Final output register
    reg18 reg_quotient_out(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N21),
        .data_out(dv_out)
    );

    // Final pipeline control
    dff1 ff14(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st12),
        .q     (valid)
    );

endmodule

////////////////////////////////////////////////
// Pre-scaling (Prescaling) Module
////////////////////////////////////////////////
module pre_scaler (
    input  logic [17:0] a,  // unsigned divisor
    input  logic [17:0] c,  // unsigned dividend
    output logic [17:0] b,  // prescaled divisor
    output logic [17:0] d   // prescaled dividend
);
    // For simplicity, if 'a' is large, we shift until it is < 1.0 in Q9.9 format
    // That means the integer bits of 'a' must be 0. We find how many leading bits
    // we need to shift out.

    always_comb begin : SHIFT_LOGIC
        // 'a' has 18 bits in total, where the top 9 bits are integer, bottom 9 bits are fractional.
        // We want the integer part of 'a' to be 0 => 'a[17:9]' should be zero after shifting.

        if (a[17]) begin
            b = a >> 8;
            d = c >> 8;
        end
        else if (a[16]) begin
            b = a >> 7;
            d = c >> 7;
        end
        else if (a[15]) begin
            b = a >> 6;
            d = c >> 6;
        end
        else if (a[14]) begin
            b = a >> 5;
            d = c >> 5;
        end
        else if (a[13]) begin
            b = a >> 4;
            d = c >> 4;
        end
        else if (a[12]) begin
            b = a >> 3;
            d = c >> 3;
        end
        else if (a[11]) begin
            b = a >> 2;
            d = c >> 2;
        end
        else if (a[10]) begin
            b = a >> 1;
            d = c >> 1;
        end
        else begin
            b = a;
            d = c;
        end
    end
endmodule

////////////////////////////////////////////////
// Single-bit DFF
////////////////////////////////////////////////
module dff1 (
    input  logic clk,
    input  logic reset,
    input  logic d,
    output logic q
);
    always_ff @(posedge clk) begin
        if (reset) 
            q <= 1'b0;
        else
            q <= d;
    end
endmodule


////////////////////////////////////////////////
// 18-bit register (parallel load)
////////////////////////////////////////////////
module reg18 (
    input  logic        clk,
    input  logic        reset,
    input  logic [17:0] data_in,
    output logic [17:0] data_out
);
    always_ff @(posedge clk) begin
        if (reset) 
            data_out <= 18'd0;
        else
            data_out <= data_in;
    end
endmodule

`timescale 1ns/1ps
module divider #
(
    parameter WIDTH = 32
)
(
    input  wire                  clk,
    input  wire                  rst_n,      // Active-low asynchronous reset
    input  wire                  start,      // Start signal for new operation
    input  wire [WIDTH-1 : 0]    dividend,   // Dividend (numerator)
    input  wire [WIDTH-1 : 0]    divisor,    // Divisor (denominator)
    output wire [WIDTH-1 : 0]    quotient,   // Result of the division
    output wire [WIDTH-1 : 0]    remainder,  // Remainder after division
    output wire                  valid       // Indicates output is valid
);

    // one extra bit for A
    localparam AW = WIDTH + 1;
    // Simple 3-state FSM
    localparam IDLE = 2'b00;
    localparam BUSY = 2'b01;
    localparam DONE = 2'b10;

    reg [1:0] state_reg, state_next;

    // A+Q combined into one WIDTH + 1 + WIDTH register:
    reg [AW+WIDTH-1 : 0] aq_reg,   aq_next;

    // Divisor register
    reg [AW-1 : 0]       m_reg,    m_next;

    // Iterate exactly WIDTH times
    reg [$clog2(WIDTH)-1:0] n_reg, n_next;

    // Final outputs
    reg [WIDTH-1:0] quotient_reg, quotient_next;
    reg [WIDTH-1:0] remainder_reg, remainder_next;
    reg valid_reg, valid_next;

    // Assign the top-level outputs
    assign quotient  = quotient_reg;
    assign remainder = remainder_reg;
    assign valid     = valid_reg;

    //------------------------------------------------
    // SEQUENTIAL: State & register updates
    //------------------------------------------------
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state_reg     <= IDLE;
            aq_reg        <= 0;
            m_reg         <= 0;
            n_reg         <= 0;
            quotient_reg  <= 0;
            remainder_reg <= 0;
            valid_reg     <= 0;
        end
        else begin
            state_reg     <= state_next;
            aq_reg        <= aq_next;
            m_reg         <= m_next;
            n_reg         <= n_next;
            quotient_reg  <= quotient_next;
            remainder_reg <= remainder_next;
            valid_reg     <= valid_next;
        end
    end

    //------------------------------------------------
    // COMBINATIONAL: Next-state logic
    //------------------------------------------------
    always @* begin
        // Default "hold" behavior
        state_next     = state_reg;
        aq_next        = aq_reg;
        m_next         = m_reg;
        n_next         = n_reg;
        quotient_next  = quotient_reg;
        remainder_next = remainder_reg;
        valid_next     = valid_reg;

        case (state_reg)
        //---------------------------------------------
        // IDLE: Wait for start
        //---------------------------------------------
        IDLE: begin
            // Outputs not valid yet
            valid_next = 1'b0;

            if (start) begin
                // Step-1: Initialize
                // A = 0 => upper AW bits all zero
                // Q = dividend => lower WIDTH bits of aq
                // so zero‐extend: { (AW)'b0, dividend }
                aq_next = { {AW{1'b0}}, dividend };
                // zero‐extend divisor into AW bits
                m_next   = {1'b0, divisor};
                n_next   = WIDTH;
                // We do not set the final quotient/remainder yet
                // Move to BUSY
                state_next = BUSY;
            end
        end

        //---------------------------------------------
        // BUSY: Perform the N iterations
        //---------------------------------------------
        BUSY: begin
            // 1) SHIFT LEFT
            aq_next = aq_reg << 1;

            // 2) If sign bit of old A == 1 => add M; else => subtract M.
            if (aq_reg[AW+WIDTH-1] == 1'b1) begin
                aq_next[AW+WIDTH-1 : WIDTH] = aq_next[AW+WIDTH-1 : WIDTH] + m_reg;
            end
            else begin
                aq_next[AW+WIDTH-1 : WIDTH] = aq_next[AW+WIDTH-1 : WIDTH] - m_reg;
            end

            // 3) Check the new sign bit of A (after the add/sub).
            //    If sign(A) = 1 => Q[0] = 0; else => Q[0] = 1.
            if (aq_next[AW+WIDTH-1] == 1'b1) begin
                aq_next[0] = 1'b0;
            end
            else begin
                aq_next[0] = 1'b1;
            end

            // Decrement iteration count
            n_next = n_reg - 1;

            // Step-7: if n != 0 => repeat, else => next step
            if (n_next == 0) begin
                state_next = DONE;
            end
        end

        //---------------------------------------------
        // DONE: Final correction + output
        //---------------------------------------------
        DONE: begin
            // Step-8: If sign bit of A == 1 => A = A + M
            if (aq_reg[AW+WIDTH-1] == 1'b1) begin
                aq_next = aq_reg;  // default
                aq_next[AW+WIDTH-1 : WIDTH] = aq_reg[AW+WIDTH-1 : WIDTH] + m_reg;
            end

            // Step-9:
            //   - The final quotient is the lower WIDTH bits of aq_reg
            //   - The final remainder is the upper WIDTH bits of aq_reg
            quotient_next  = aq_next[WIDTH-1 : 0];
            remainder_next = aq_next[2*WIDTH-1 : WIDTH];

            // Output becomes valid
            valid_next = 1'b1;

            // Return to IDLE when 'start' goes low
            if (!start) begin
                state_next = IDLE;
            end else begin
                state_next = DONE;
            end
        end

        default: begin
            state_next = IDLE;
        end
        endcase
    end

endmodule

