         acc_result <= 0;
      else if (sum_en)
         acc_result <= mid_prod;
      else if (messy_flag[3])
         acc_result <= acc_result + { {(OW-(IW+TW)){mult_result[IW+TW-1]}}, mult_result };
    end

    // --- Output Assignments ---
    initial o_result = 0;
    always @(posedge i_clk)
       if (sum_en)
          o_result <= acc_result;

    // --- Output Clock Enable Update ---
    initial o_ce = 1'b0;
    always @(posedge i_clk)
       o_ce <= (sum_en && !i_reset);

endmodule

