module fsm (
    input clock,
    input reset,
    input start,
    output done
);

    // State definitions
    enum state { IDLE, PROCESS, DONE };

    // Current state
    reg state = IDLE;

    // State transition table
    always @(posedge clock or negedge reset) begin
        if (reset) begin
            state = IDLE;
        end else if (start) begin
            if (state == IDLE) begin
                state = PROCESS;
            end else if (state == PROCESS) begin
                state = DONE;
            end
        end
    end
end

// Key Matrix Declaration
reg [[8]] key_matrix[3][3];
initial begin
    key_matrix[0][0] = 3;
    key_matrix[0][1] = 10;
    key_matrix[0][2] = 20;
    key_matrix[1][0] = 1;
    key_matrix[1][1] = 9;
    key_matrix[1][2] = 15;
    key_matrix[2][0] = 8;
    key_matrix[2][1] = 7;
    key_matrix[2][2] = 17;
end

// Plaintext Vector Declaration
reg [[15]] plaintext;
always begin
    // Plaintext mapping
    plaintext[14:10] = 2;
    plaintext[9:5] = 0;
    plaintext[4:0] = 19;
end

// Ciphertext Vector Declaration
reg [[15]] ciphertext;
always begin
    // Ciphertext mapping
    ciphertext[14:10] = 22;
    ciphertext[9:5] = 1;
    ciphertext[4:0] = 1;
end

// FSM State Machine
always @posedge clock begin
    if (state == IDLE) begin
        // Initialization
        // Wait for start signal
    end else if (state == PROCESS) begin
        // Perform matrix multiplication
        // Compute C0
        integer sum = 0;
        sum = (sum + key_matrix[0][0] * plaintext[14:10]) % 26;
        sum = (sum + key_matrix[0][1] * plaintext[9:5]) % 26;
        sum = (sum + key_matrix[0][2] * plaintext[4:0]) % 26;
        ciphertext[14:10] = sum;

        // Compute C1
        sum = 0;
        sum = (sum + key_matrix[1][0] * plaintext[14:10]) % 26;
        sum = (sum + key_matrix[1][1] * plaintext[9:5]) % 26;
        sum = (sum + key_matrix[1][2] * plaintext[4:0]) % 26;
        ciphertext[9:5] = sum;

        // Compute C2
        sum = 0;
        sum = (sum + key_matrix[2][0] * plaintext[14:10]) % 26;
        sum = (sum + key_matrix[2][1] * plaintext[9:5]) % 26;
        sum = (sum + key_matrix[2][2] * plaintext[4:0]) % 26;
        ciphertext[4:0] = sum;

        // Transition to DONE state after 3 clock cycles
        if (posedge clock) begin
            state = DONE;
        end
    end else if (state == DONE) begin
        // Output ciphertext after 3 clock cycles
        // No action needed as ciphertext is already computed
    end
end

// Done Signal Declaration
always @posedge clock begin
    if (state == DONE) begin
        // Output ciphertext
        done = 1;
    end
end
endmodule

