module image_stego #(
  parameter row = 2,
  parameter col = 2
)(
  input  [(row*col*8)-1:0] img_in,
  input  [(row*col*4)-1:0] data_in,
  input  [1:0]             bpp,
  output [(row*col*8)-1:0] img_out
);

  genvar i;
  generate
    for(i = 0; i < row*col; i++) begin
      assign img_out[(i*8)+7:(i*8)] = (bpp[1] == 1'b0)
                                      ? (bpp[0] == 1'b0
                                         ? {img_in[(i*8)+7 : (i*8)+1], data_in[i]}
                                         : {img_in[(i*8)+7 : (i*8)+2], data_in[(2*i)+1], data_in[2*i]}) 
                                      : img_in[(i*8)+7 : (i*8)]; 
    end
  endgenerate

endmodule

output.rtl/image_stego.sv:
module image_stego #(
  parameter row = 2,
  parameter col = 2
)(
  input  [(row*col*8)-1:0] img_in,
  input  [(row*col*4)-1:0] data_in,
  input  [1:0]             bpp,
  output [(row*col*8)-1:0] img_out
);

  genvar i;
  generate
    for(i = 0; i < row*col; i++) begin
      if (bpp == 2'b10 || bpp == 2'b11) begin
        assign img_out[(i*8)+7:(i*8)] = (bpp[1] == 1'b1
                                       ? {img_in[(i*8)+7 : (i*8)+2], data_in[2*i], data_in[2*i+1]} 
                                       : img_in[(i*8)+7 : (i*8)]);
      else begin
        assign img_out[(i*8)+7:(i*8)] = (bpp[1] == 1'b0
                                       ? {img_in[(i*8)+7 : (i*8)+1], data_in[i]}
                                       : img_in[(i*8)+7 : (i*8)]);
      end
    end
  endgenerate

endmodule

output.rtl/programmable_interrupt_controller.sv:
module interrupt_controller 
#(
    parameter NUM_INTERRUPTS = 4, 
    parameter ADDR_WIDTH = 8)
(
    input  logic                      clk,
    input  logic                      rst_n,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic                      cpu_interrupt,
    input  logic                      cpu_ack,
    output logic [ADDR_WIDTH-1:0]     interrupt_vector,
    input  logic [NUM_INTERRUPTS-1:0] priority_map_value [NUM_INTERRUPTS-1:0],
    input  logic                      priority_map_update,
    input  logic [ADDR_WIDTH-1:0]     vector_table_value [NUM_INTERRUPTS-1:0],
    input  logic                      vector_table_update,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_mask_value,
    input  logic                      interrupt_mask_update
);

    // Initialize registers on reset
    logic [NUM_INTERRUPTS-1:0] priority_map [NUM_INTERRUPTS-1:0];
    logic [NUM_INTERRUPTS-1:0] vector_table [ADDR_WIDTH-1:0];
    logic [NUM_INTERRUPTS-1:0] interrupt_mask;
    logic [NUM_INTERRUPTS-1:0] pending_interrupts;
    logic current_interrupt;

    // Initialize to default values on reset
    initial begin
        priority_map = { replicate({i: 1}, NUM_INTERRUPTS) };
        vector_table = { replicate({i*4}, ADDR_WIDTH) };
        interrupt_mask = 0;
        pending_interrupts = 0;
    end

    // Always update priority map
    always priority_map_value when priority_map_update;
    assign priority_map = priority_map_value;

    // Always update vector table
    always vector_table_value when vector_table_update;
    assign vector_table = vector_table_value;

    // Always update interrupt mask
    always interrupt_mask_value when interrupt_mask_update;
    assign interrupt_mask = interrupt_mask_value;

    // Main processing logic
    process (clk, cpu_ack) begin
        // Check if any interrupts are pending and not masked
        pending_interrupts = 0;
        current_interrupt = 0;
        for (int i = 0; i < NUM_INTERRUPTS; i++) begin
            if (priority_mask[i] & pending_interrupts & !interrupt_mask[i]) begin
                current_interrupt = i;
                break;
            end
        end

        // If an interrupt is being serviced
        if (current_interrupt != 0) begin
            // Set the interrupt vector
            interrupt_vector = vector_table[current_interrupt];

            // Notify the CPU
            cpu_interrupt = 1;

            // Wait for CPU acknowledgment
            while (1) begin
                if (cpu_ack) begin
                    cpu_interrupt = 0;
                    break;
                end
                // Prevent multiple service completions in one cycle
                else begin
                    cpu_interrupt = 0;
                end
            end
        else begin
            // Clear any pending service
            pending_interrupts = 0;
        end
    end

endmodule

output.rtl/pic_starvation_prevention.sv:
module interrupt_controller (
    input wire clk,
    input wire rst_n,
    input wire reset_interrupts,
    input wire [9:0] interrupt_requests,
    input wire interrupt_ack,
    input wire interrupt_trig,
    input wire [9:0] interrupt_mask,
    input wire [3:0] priority_override,
    input wire [3:0] override_interrupt_id,
    input wire priority_override_en,
    output reg [3:0] interrupt_id,
    output reg interrupt_valid,
    output reg [9:0] interrupt_status,
    output reg [9:0] missed_interrupts,
    output reg starvation_detected
);

    parameter STARVATION_THRESHOLD = 5;

    localparam [2:0] 
        IDLE = 3'b000,
        PRIORITY_CALC = 3'b001,
        SERVICE_PREP = 3'b010,
        SERVICING = 3'b011,
        COMPLETION = 3'b100,
        ERROR = 3'b111;

    reg [2:0] current_state, next_state;
    reg [9:0] pending_interrupts;
    reg [3:0] wait_counters [0:9];
    reg [4:0] effective_priority [0:9];
    reg [3:0] active_mask;
    reg [3:0] service_timer;
    reg timeout_error;
    reg [3:0] next_interrupt_id;
    reg [4:0] max_priority;

    always @posedge clk or (!rst_n & asserted(reset_interrupts)) begin
        current_state = IDLE;
        next_state = IDLE;
    end

    always @negedge rst_n begin
        current_state = IDLE;
        next_state = IDLE;
    end

    // State: IDLE
    always @negedge rst_n or (!rst_n & !reset_interrupts) begin
        if (interrupt_trig) begin
            current_state = PRIORITY Calc;
        end
    end

    // State: PRIORITY Calc
    always @negedge rst_n or (!rst_n & current_state == PRIORITY Calc) begin
        // Calculate effective priority
        effective_priority = max_priority;
        for (int i = 0; i < 10; i++) begin
            if (wait_counters[i] > STARVATION_THRESHOLD) begin
                effective_priority[i] = max_priority[i] + 1;
            end
        end

        // Apply priority override if enabled
        if (priority_override_en) begin
            effective_priority = (priority_override << 2) | (priority_override_en ? 0 : max_priority);
        end

        // Select highest priority interrupt
        next_interrupt_id = 0;
        for (int i = 0; i < 10; i++) begin
            if (effective_priority[i] > effective_priority[next_interrupt_id]) begin
                next_interrupt_id = i;
            end
        end

        current_state = SERVICE_PREP;
        next_state = next_state;
    end

    // State: SERVICE_PREP
    always @negedge rst_n or (!rst_n & current_state == SERVICE_PREP) begin
        // Prepare to service interrupt
        service_timer = 0;
        next_state = SERVICING;
    end

    // State: SERVICING
    always @negedge rst_n or (!rst_n & current_state == SERVICING) begin
        // Service the interrupt
        service_timer = service_timer + 1;
        next_state = COMPLETION;
    end

    // State: COMPLETION
    always @negedge rst_n or (!rst_n & current_state == COMPLETION) begin
        // Reset state and clear status
        current_state = IDLE;
        next_state = IDLE;
    end

    // Error handling
    always @negedge rst_n or (!rst_n & current_state == ERROR) begin
        // Set error flag
        timeout_error = 1;
    end

    // Mask handling
    always @negedge rst_n or (!rst_n & current_state == IDLE) begin
        active_mask = interrupt_mask;
    end

    // Update missed interrupts
    always @negedge rst_n or (!rst_n & current_state == IDLE) begin
        for (int i = 0; i < 10; i++) begin
            if (active_mask & (1 << i)) begin
                missed_interrupts[i] = missed_interrupts[i] + 1;
            end
        end
    end

    // Update wait counters
    always @negedge rst_n or (!rst_n & current_state == IDLE) begin
        for (int i = 0; i < 10; i++) begin
            if (!active_mask & (1 << i)) begin
                wait_counters[i] = 0;
            end
        end
    end

    // Update pending interrupts
    always @negedge rst_n or (!rst_n & current_state == IDLE) begin
        pending_interrupts = 0;
    end

output.rtl/interrupt_controller_apb.sv:
module interrupt_controller_apb #(
    parameter NUM_INTERRUPTS = 4,
    parameter ADDR_WIDTH = 8
    )
    (
    input  logic                      clk,
    input  logic                      rst_n,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic                      cpu_interrupt,
    input  logic                      cpu_ack,
    output  logic [$clog2(NUM_INTERRUPTS)-1:0] interrupt_idx,
    output logic [ADDR_WIDTH-1:0]     interrupt_vector,

    // APB Interface Signals
    input  logic                      pclk,
    input  logic                      presetn,
    input  logic                      psel,
    input  logic                      penable,
    input  logic                      pwrite,
    input  logic [ADDR_WIDTH-1:0]     paddr,
    input  logic [31:0]               pwdata,
    output logic [31:0]               prdata,
    output logic                      pready
);

    logic [NUM_INTERRUPTS-1:0] interrupt_mask;
    logic servicing;
    logic [NUM_INTERRUPTS-1:0] pending_interrupts;
    logic [NUM_INTERRUPTS-1:0] vector_table;

    // Initialize default values
    initial begin
        interrupt_mask = (1 << NUM_INTERRUPTS) - 1;
        pending_interrupts = 0;
        vector_table = 0;
        // Initialize priority map with default priorities
        for (logic i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
            priority_map[i] = i;
        end
    end

    // APB clock generation
    pclk = !clk;

    // APB ready handling
    pready = 0;
    always_comb begin
        if (serving) begin
            pready = 1;
            servicing = false;
        end
    end

    // Handle interrupt requests
    always logic begin
        if (rst_n) begin
            servicing = false;
            pending_interrupts = 0;
            vector_table = 0;
            // Initialize priority map on reset
            for (logic i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
                priority_map[i] = i;
            end
        end else begin
            if (interrupt_requests) begin
                // Update pending interrupts
                pending_interrupts = pending_interrupts | interrupt_requests;

                // Select highest priority interrupt
                servicing = true;
                interrupt_idx = 0;
                interrupt_vector = 0;
                logic max_priority = 0;
                logic max_index = 0;

                for (logic i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
                    if (priority_map[i] > max_priority) begin
                        max_priority = priority_map[i];
                        max_index = i;
                    end
                end
                interrupt_idx = max_index;
                interrupt_vector = vector_table[max_index];
            end
        end
    end

    // APB write operation
    if (psel & penable & pwrite) begin
        prdata = pwdata;
    end

    // APB read operation
    if (psel & penable & ~pwrite) begin
        prdata = paddr;
    end

    endmodule

output.rtl/ir_receiver.sv:
module ir_receiver (
    input  logic        reset_in,       // Active HIGH reset
    input  logic        clk_in,         // System clock (100 KHz, 10us)
    input  logic        ir_signal_in,   // Input signal (IR)
    output logic [11:0] ir_frame_out,   // Decoded 12-bit frame
    output logic        ir_frame_valid  // Indicates validity of the decoded frame
);

    typedef enum logic [1:0] {idle, start, decoding, finish} ir_state;
    ir_state present_state, next_state;

    logic started; 
    logic decoded; 
    logic failed; 
    logic success;

    int cycle_counter; 
    int bit_counter;          

    logic [11:0] ir_frame_reg; 
    logic stored;                       

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idle;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idle: begin
                // Start bit detection
                if (!reset_in) begin
                    if (ir_signal_in && (!clkin || (cycle_counter == 0))) begin
                        // 2.4ms high pulse detected
                        bit_counter = 0;
                        started = true;
                    end
                end
                next_state = start;
            end

            start: begin
                if (started) begin
                    if (bit_counter == 12) begin
                        // All 12 bits received
                        ir_frame_reg = stored;
                        decoded = true;
                        next_state = finish;
                    end else begin
                        // Check current bit
                        logic current_bit;
                        if (ir_signal_in) begin
                            // High pulse detected after low pulse
                            current_bit = 1;
                        end else begin
                            current_bit = 0;
                        end
                        if (current_bit == 0) begin
                            // 0.6ms high pulse
                            if (clkin) begin
                                // Valid 0 bit
                                stored = (stored << 1) | 0;
                                bit_counter = bit_counter + 1;
                                next_state = start;
                            end else begin
                                // Invalid bit
                                started = false;
                                failed = true;
                                next_state = idle;
                            end
                        end else begin
                            // 1.2ms high pulse
                            if (clkin) begin
                                // Valid 1 bit
                                stored = (stored << 1) | 1;
                                bit_counter = bit_counter + 1;
                                next_state = start;
                            end else begin
                                // Invalid bit
                                started = false;
                                failed = true;
                                next_state = idle;
                            end
                        end
                    end
                end
                next_state = idle;
            end

            decoding: begin
                // Already in decoding state
                next_state = decoding;
            end

            finish: begin
                // Frame complete
                ir_frame_valid = 1;
                next_state = idle;
            end
        end
    end

    wire (
        cycle_counter = (posedge clk_in) ? (posedge clk_in ? 0 : cycle_counter + 1) : 0
    );
    wire (
        bit_counter = (posedge clk_in) ? (posedge clk_in ? 0 : bit_counter + 1) : 0
    );

    initial begin
        // Initial state
        present_state = idle;
        next_state = start;
    end
endmodule

module ir_receiver (
    input  logic        reset_in,               // Active HIGH reset
    input  logic        clk_in,                 // System clock (10 KHz, 100us)
    input  logic        ir_signal_in,           // Input signal (IR)
    output logic [6:0]  ir_function_code_out,   // Decoded output for different functions
    output logic [4:0]  ir_device_address_out,  // "00001": TV, "00010":HDMI1, "00100":USB, "01000":HDMI2, "10000": VCR
    output logic        ir_output_valid         // Indicates validity of the decoded frame
);

    typedef enum logic [2:0] {idle, start, decoding, finish, frame_space} ir_state;
    ir_state present_state, next_state;

    logic started;
    logic decoded;
    logic failed;
    logic success;
    logic frame_full;
    logic ir_frame_valid;

    int cycle_counter;
    int frame_space_counter;
    int bit_counter;

    logic [11:0] ir_frame_reg;
    logic [11:0] ir_frame_out;
    logic stored;

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idle;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idle: begin
                if (ir_signal_in == 1 && started == 0)
                    next_state = start;
                else
                    next_state = idle;
            end
            start: begin
                if (ir_signal_in == 0 && started == 1)
                    next_state = decoding;
                else if (failed == 1)
                    next_state = idle;
                else
                    next_state = start;
            end
            decoding: begin
                if (decoded == 1)
                    next_state = finish;
                else if (failed == 1)
                    next_state = idle;
                else
                    next_state = decoding;
            end
            finish: begin
                if (success == 1)
                    next_state = frame_space;
                else
                    next_state = finish;
            end

            // Decoding logic
            decoding: begin
                if (bit_counter == 12) begin
                    frame_full = 1;
                    ir_frame_valid = 1;
                    bit_counter = 0;
                end
                bit_counter = bit_counter + 1;
                ir_frame_reg[bit_counter] = ir_signal_in;
                next_state = decoding;
            end
        end
    end

    // Address decoding
    decoding: begin
        logic [4:0] address = ir_frame_reg[10:5];
        ir_device_address_out = address;
    end

    // Function code decoding
    decoding: begin
        logic [7:0] function_code = ir_frame_reg[5:0];
        case (function_code)
            0b0000000 => ir_function_code_out = 7'b0000000;
            0b0000001 => ir_function_code_out = 7'b0000001;
            0b0000002 => ir_function_code_out = 7'b0000010;
            0b0000003 => ir_function_code_out = 7'b0000011;
            0b0000004 => ir_function_code_out = 7'b0000100;
            0b0000005 => ir_function_code_out = 7'b0000101;
            0b0000006 => ir_function_code_out = 7'b0000110;
            0b0000007 => ir_function_code_out = 7'b0000111;
            0b0000010 => ir_function_code_out = 7'b0001000;
            0b0000011 => ir_function_code_out = 7'b0001001;
            0b0000012 => ir_function_code_out = 7'b0001010;
            0b0000013 => ir_function_code_out = 7'b0001011;
            0b0000014 => ir_function_code_out = 7'b0001100;
            0b0000015 => ir_function_code_out = 7'b0001101;
            0b0000016 => ir_function_code_out = 7'b0001110;
            0b0000017 => ir_function_code_out = 7'b0001111;
            0b0000018 => ir_function_code_out = 7'b0010000;
            0b0000019 => ir_function_code_out = 7'b0010001;
            0b0000020 => ir_function_code_out = 7'b0010010;
            0b0000021 => ir_function_code_out = 7'b0010011;
            0b0000022 => ir_function_code_out = 7'b0010100;
            0b0000023 => ir_function_code_out = 7'b0010101;
            0b0000024 => ir_function_code_out = 7'b0010110;
            0b0000025 => ir_function_code_out = 7'b0010111;
            0b0000026 => ir_function_code_out = 7'b0011000;
            0b0000027 => ir_function_code_out = 7'b0011001;
            0b0000028 => ir_function_code_out = 7'b0011010;
            0b0000029 => ir_function_code_out = 7'b0011011;
            0b0000030 => ir_function_code_out = 7'b0011100;
            0b0000031 => ir_function_code_out = 7'b0011101;
            0b0000032 => ir_function_code_out = 7'b0011110;
            0b0000033 => ir_function_code_out = 7'b0011111;
            default case begin
                ir_function_code_out = 7'b0000000;
                failed = 1;
            end
        end
    end

    finish: begin
        ir_output_valid = 1;
        present_state = frame_space;
        bit_counter = 0;
    end

    frame_space: begin
        present_state = idle;
    end
endmodule

