output.rtl/packet_controller.sv:
module packet_controller(
    input clock,
    input rst,
    input rx_valid_i,
    input [7:0] rx_data_8_i,
    input tx_done_tick_i,
    output tx_start_o,
    output [7:0] tx_data_8_o
);

    // State variables
    enum state_t state = S_IDLE;
    enum state_t current_opcode = 0;

    // FIFO buffer for accumulating received data
    FIFO FIFO(8)fifo;

    // State transition table
    always @posedge clock begin
        case (state)
            S_IDLE:
                if (rst) state = S_IDLE; // Active-high reset
                else if (rx_valid_i) begin
                    fifo.push(rx_data_8_i);
                    if (fifo.size() == 8) state = S_GOT_8_BYTES;
                end
            S_GOT_8_BYTES:
                if (fifo.size() == 8) begin
                    byte_t [7:0] received = fifo.pop();
                    if (received[16:0] != 0x1234) state = S_IDLE; // Invalid header
                    else begin
                        byte_t sum = 0;
                        for (int i = 0; i < 8; i++) sum += fifo.pop()[7:0];
                        if (sum % 256 != 0) state = S_IDLE; // Invalid checksum
                        else state = S_RECV_CHECKSUM;
                    end
                end
            S_RECV_CHECKSUM:
                if (rx_valid_i) begin
                    byte_t [7:0] received = rx_data_8_i;
                    if (received != 0x1234) state = S_IDLE; // Invalid checksum
                    else state = S_BUILD_RESPONSE;
                end
            S_BUILD_RESPONSE:
                byte_t [7:0] payload;
                case (current_opcode)
                    0x00: payload = rx_data_8_i;
                    0x01: payload = rx_data_8_i;
                    default: payload = 0;
                endcase
                fifo.write(0x1234);
                fifo.write(payload);
                state = S_SEND_FIRST_BYTE;
            S_SEND_FIRST_BYTE:
                if (tx_done_tick_i) begin
                    fifo.write(payload);
                    if (fifo.size() == 5) state = S_RESPONSE_READY;
                end
            S_RESPONSE_READY:
                if (tx_done_tick_i) state = S_IDLE;
        endcase
    end

    // Output the accumulated data when done
    always @posedge clock begin
        if (state == S_RESPONSE_READY) begin
            tx_start_o = 1;
            tx_data_8_o = fifo.pop();
            fifo.write(fifo.pop());
            fifo.write(fifo.pop());
            fifo.write(fifo.pop());
            fifo.write(fifo.pop());
            fifo.write(fifo.pop());
            fifo.write(fifo.pop());
            fifo.write(fifo.pop());
        end
    end

    // Initial state setup
    initial begin
        state = S_IDLE;
        current_opcode = 0;
    end

endmodule

output.rtl/palindrome_detect.sv:
module palindrome_detect #( 
parameter N=3
) (
input clk,
input reset,
input bit_stream,
output palindrome_detected
);

reg reg1, reg2, reg3;
reg counter, detection_flag;

if (!reset) begin
  reg1 = 0;
  reg2 = 0;
  reg3 = 0;
  counter = 0;
  detection_flag = 0;
end

if (counter == N-1) begin
  reg1 = bit_stream;
  reg2 = reg1;
  reg3 = reg2;
  counter = N;

  if (reg1 == reg3) begin
    detection_flag = 1;
  end

  // Reset on next clock cycle
  #2
  detection_flag = 0;
  counter = 0;
end

// Output the detection flag on the next clock cycle
#1
palindrome_detected = detection_flag;

endmodule

output.rtl/password_generator.sv:
module password_generator #(
    parameter WIDTH = 4  
) (
    input logic clk,
    input logic reset,
    output logic [(WIDTH*8)-1:0] password 
);

  logic [7:0] char_array[WIDTH-1:0];  
  logic [7:0] counter;  
  logic [1:0] char_type; 

  int i;

  always_comb begin
    if (reset) begin
      counter = 0;
      char_array = {WIDTH{0}}; // Initialize all to 0
    end
  end

  always_edge begin
    if (clk) begin
      counter = counter + 1;
      for (i = 0; i < WIDTH; i = i + 1) begin
        case (char_type)
          00: 
            char_array[i] = ((counter + char_array[(i+1) % WIDTH]) % 26) + 8'd97;
            break;
          01: 
            char_array[i] = ((counter + i) % 26) + 8'd65;
            break;
          10: 
            char_array[i] = ((counter + char_array[(i+WIDTH-1) % WIDTH]) % 14) + 8'd33;
            break;
          11: 
            char_array[i] = ((counter + i) % 10) + 8'd48;
            break;
        end
      end
    end
  end

endmodule

output.rtl/perceptron_gates.sv:
module perceptron_gates(
    input clock,
    input rst_n,
    input [3:0] x1,
    input [3:0] x2,
    input learning_rate,
    input [3:0] threshold,
    input [1:0] gate_select
    output reg percep_w1,
    output reg percep_w2,
    output reg percep_bias,
    output reg present_addr,
    output reg stop,
    output reg input_index,
    output reg [3:0] y_in,
    output reg [3:0] y
);

// Microcode ROM instructions
reg [5:0] microcode_rom = [
    6'd0: 4'd0, 4'd0, 4'd0, 4'd0, 4'd0, 4'd0,
    6'd1: 4'd0, 4'd0, 4'd0, 4'd0, 4'd0, 4'd0,
    6'd2: 4'd0, 4'd0, 4'd0, 4'd0, 4'd0, 4'd0,
    6'd3: 4'd0, 4'd0, 4'd0, 4'd0, 4'd0, 4'd0,
    6'd4: 4'd0, 4'd0, 4'd0, 4'd0, 4'd0, 4'd0,
    6'd5: 4'd0, 4'd0, 4'd0, 4'd0, 4'd0, 4'd0
];

// Initialize weights and biases
reg [3:0] prev_percep_w1, prev_percep_w2, prev_percep_bias;
reg [3:0] percep_w1, percep_w2, percep_bias;
reg [3:0] y_in, y;
reg [3:0] input_index;

// Target values based on gate type
reg [4:0] o_1, o_2, o_3, o_4;
always @* begin
    case(gate_select)
        2'b00: o_1 = 4'd1; o_2 = -4'd1; o_3 = -4'd1; o_4 = -4'd1;
        2'b01: o_1 = 4'd1; o_2 = 4'd1; o_3 = 4'd1; o_4 = -4'd1;
        2'b10: o_1 = 4'd1; o_2 = 4'd1; o_3 = 4'd1; o_4 = -4'd1;
        2'b11: o_1 = 4'd1; o_2 = -4'd1; o_3 = -4'd1; o_4 = -4'd1;
    endcase
end

// Main training loop
always @posedge clock begin
    if (rst_n) begin
        percep_w1 = 4'd0;
        percep_w2 = 4'd0;
        percep_bias = 4'd0;
        present_addr = 4'd0;
        stop = 1;
        input_index = 3'd0;
        y_in = 4'd0;
        y = 4'd0;
        present_addr = 4'd5;
        // Start training with first input vector
        present_addr = 4'd1;
        #10ns;
    end else begin
        // Execute microcode ROM instruction
        case(present_addr)
            6'd0: begin
                // Initialization
                percep_w1 = 4'd0;
                percep_w2 = 4'd0;
                percep_bias = 4'd0;
                present_addr = 4'd1;
                #10ns;
            end
            6'd1: begin
                // Compute perceptron output
                y_in = (x1 & percep_w1) + (x2 & percep_w2) + percep_bias;
                y = y_in > threshold ? 4'd1 : -4'd1;
                present_addr = 4'd2;
                #10ns;
            end
            6'd2: begin
                // Select target
                case(gate_select)
                    2'b00: o_1 = 4'd1; o_2 = -4'd1; o_3 = -4'd1; o_4 = -4'd1;
                    2'b01: o_1 = 4'd1; o_2 = 4'd1; o_3 = 4'd1; o_4 = -4'd1;
                    2'b10: o_1 = 4'd1; o_2 = 4'd1; o_3 = 4'd1; o_4 = -4'd1;
                    2'b11: o_1 = 4'd1; o_2 = -4'd1; o_3 = -4'd1; o_4 = -4'd1;
                endcase
                present_addr = 4'd3;
                #10ns;
            end
            6'd3: begin
                // Update weights and bias
                if (y != o_1) begin
                    wt1_update = learning_rate & (x1 & o_1);
                    wt2_update = learning_rate & (x2 & o_1);
                    bias_update = learning_rate & o_1;
                else begin
                    wt1_update = 4'd0;
                    wt2_update = 4'd0;
                    bias_update = 4'd0;
                end
                percep_w1 = percep_w1 + wt1_update;
                percep_w2 = percep_w2 + wt2_update;
                percep_bias = percep_bias + bias_update;
                present_addr = 4'd4;
                #10ns;
            end
            6'd4: begin
                // Check for convergence
                if (percep_w1 == prev_percep_w1 &
                    percep_w2 == prev_percep_w2 &
                    percep_bias == prev_percep_bias) begin
                    stop = 1;
                    present_addr = 4'd5;
                else begin
                    prev_percep_w1 = percep_w1;
                    prev_percep_w2 = percep_w2;
                    prev_percep_bias = percep_bias;
