    wire [ (log2(N/2)+1)-1 : 0 ] pairs_in_this_pass;

    assign pairs_in_this_pass = (state[1] == 1'b0) ? (N/2) : ( (N/2) > 0 ? (N/2) - 1 : 0 );

    // Load data
    always @ (start) begin
        if (rst) begin
            data_array = { data_array[0:0], data_array[1:0] };
        end
        data_array = in_data;
    end

    // Sort data
    always @ (posedge clk) begin
        if (rst) next_state = IDLE;
        else if (state == IDLE) begin
            state = LOAD;
            next_state = LOAD;
        elsif (state == LOAD) begin
            state = SORT;
            next_state = SORT;
        elsif (state == SORT) begin
            // Even pass
            if (state[1] == 0) begin
                for (pair_idx = 0; pair_idx < N/2; pair_idx++, state = next_state) {
                    if (data_array[2*pair_idx] > data_array[2*pair_idx+1]) {
                        data_array[2*pair_idx], data_array[2*pair_idx+1] = data_array[2*pair_idx+1], data_array[2*pair_idx];
                    }
                }
                next_state = SORT;
            end
            // Odd pass
            else begin
                for (pair_idx = 0; pair_idx < (N/2)-1; pair_idx++, state = next_state) {
                    if (data_array[2*pair_idx+1] > data_array[2*pair_idx+2]) {
                        data_array[2*pair_idx+1], data_array[2*pair_idx+2] = data_array[2*pair_idx+2], data_array[2*pair_idx+1];
                    }
                }
                next_state = DONE;
            end
        end
        state = next_state;
    end

    // Pack sorted data
    always @ (posedge clk) begin
        if (rst) begin
            out_data = 0;
            done = 0;
        end
        else if (state == DONE) begin
            out_data = data_array;
            done = 1;
        end
        else begin
            out_data = data_array;
        end
    end

module sorting_engine #(
    parameter N = 8,
    parameter WIDTH = 8
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    //-----------------------------------------------------
    // State machine definitions
    //-----------------------------------------------------
    localparam [3:0]
        S_IDLE         = 4'd0,
        S_LOAD_INPUT   = 4'd1,
        S_FIND_MAX     = 4'd2,
        S_COUNT        = 4'd3,
        S_PREFIX_SUM   = 4'd4,
        S_BUILD_OUTPUT = 4'd5,
        S_COPY_OUTPUT  = 4'd6,
        S_DONE         = 4'd7;

    //-----------------------------------------------------
    // Registered signals (updated in sequential always)
    //-----------------------------------------------------
    reg [3:0]           current_state;
    reg [WIDTH-1:0]     data_array [0:N-1];
    reg [WIDTH-1:0]     out_array  [0:N-1];
    reg [$clog2(N):0]   count_array[0:(1<<WIDTH)-1];

    reg [WIDTH-1:0]     max_val;
    reg [$clog2(N):0]   load_cnt;
    reg [$clog2(N):0]   find_cnt;
    reg [$clog2(N):0]   count_cnt;
    reg [WIDTH-1:0]     prefix_cnt;
    reg [$clog2(N):0]   build_cnt;
    reg [WIDTH-1:0]     copy_cnt;

    //-----------------------------------------------------
    // Wires/reg for "next" values (computed combinationally)
    //-----------------------------------------------------
    reg [3:0]           next_state;

    // Arrays get "shadow copies" for combinational updates
    reg [WIDTH-1:0]     next_data_array [0:N-1];
    reg [WIDTH-1:0]     next_out_array  [0:N-1];
    reg [$clog2(N):0]   next_count_array[0:(1<<WIDTH)-1];

    reg [WIDTH-1:0]     next_max_val;
    reg [$clog2(N):0]   next_load_cnt;
    reg [$clog2(N):0]   next_find_cnt;
    reg [$clog2(N):0]   next_count_cnt;
    reg [WIDTH-1:0]     next_prefix_cnt;
    reg [$clog2(N):0]   next_build_cnt;
    reg [$clog2(N):0]   next_copy_cnt;

    reg                 next_done;
    reg [N*WIDTH-1:0]   next_out_data;
    integer rev_idx;
    reg [WIDTH-1:0] val;
    reg [$clog2(N):0] pos;

    integer i;
    always @(*) begin
        if (rst) begin
            current_state <= S_IDLE;
            done          <= 1'b0;
            out_data      <= {N*WIDTH{1'b0}};
            max_val       <= {WIDTH{1'b0}};

            load_cnt      <= 0;
            find_cnt      <= 0;
            count_cnt     <= 0;
            prefix_cnt    <= 0;
            build_cnt     <= 0;
            copy_cnt      <= 0;

            for (i = 0; i < N; i = i + 1) begin
                data_array[i] <= {WIDTH{1'b0}};
                out_array[i]  <= {WIDTH{1'b0}};
            end
            for (i = 0; i < (1<<WIDTH); i = i + 1) begin
                count_array[i] <= {($clog2(N)+1){1'b0}};
            end
        else begin
            case (current_state)
                S_IDLE:
                    current_state = S_LOAD_INPUT;
                    load_cnt = 1;
                    next_state = S_LOAD_INPUT;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt + 1;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt;
                    next_done = done;
                    next_out_data = out_data;

                S_LOAD_INPUT:
                    if (start) begin
                        load_cnt = 1;
                        next_state = S_FIND_MAX;
                        next_data_array = data_array;
                        next_out_array = out_array;
                        next_count_array = count_array;
                        next_max_val = max_val;
                        next_load_cnt = load_cnt + 1;
                        next_find_cnt = find_cnt;
                        next_count_cnt = count_cnt;
                        next_prefix_cnt = prefix_cnt;
                        next_build_cnt = build_cnt;
                        next_copy_cnt = copy_cnt;
                        next_done = done;
                    end
                    load_cnt <= load_cnt + 1;

                S_FIND_MAX:
                    find_cnt = 1;
                    next_state = S_COUNT;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt + 1;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt;
                    next_done = done;

                S_COUNT:
                    count_cnt = 1;
                    next_state = S_PREFIX_SUM;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt + 1;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt;
                    next_done = done;

                S_PREFIX_SUM:
                    prefix_cnt = 1;
                    next_state = S_BUILD_OUTPUT;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt + 1;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt;
                    next_done = done;

                S_BUILD_OUTPUT:
                    build_cnt = 1;
                    next_state = S_COPY_OUTPUT;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt + 1;
                    next_copy_cnt = copy_cnt;
                    next_done = done;

                S_COPY_OUTPUT:
                    copy_cnt = 1;
                    next_state = S_DONE;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt + 1;
                    next_done = done;

                S_DONE:
                    done <= 1'b1;
                    out_data <= out_array;
                    current_state <= S_IDLE;
            end
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            current_state <= S_IDLE;
            done          <= 1'b0;
            out_data      <= {N*WIDTH{1'b0}};
            max_val       <= {WIDTH{1'b0}};

            load_cnt      <= 0;
            find_cnt      <= 0;
            count_cnt     <= 0;
            prefix_cnt    <= 0;
            build_cnt     <= 0;
            copy_cnt      <= 0;

            for (i = 0; i < N; i = i + 1) begin
                data_array[i] <= {WIDTH{1'b0}};
                out_array[i]  <= {WIDTH{1'b0}};
            end
            for (i = 0; i < (1<<WIDTH); i = i + 1) begin
                count_array[i] <= {($clog2(N)+1){1'b0}};
            end
        else begin
            case (current_state)
                S_IDLE:
                    current_state = S_LOAD_INPUT;
                    load_cnt = 1;
                    next_state = S_LOAD_INPUT;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt + 1;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt;
                    next_done = done;
                    next_out_data = out_data;

                S_LOAD_INPUT:
                    if (start) begin
                        load_cnt = 1;
                        next_state = S_FIND_MAX;
                        next_data_array = data_array;
                        next_out_array = out_array;
                        next_count_array = count_array;
                        next_max_val = max_val;
                        next_load_cnt = load_cnt + 1;
                        next_find_cnt = find_cnt;
                        next_count_cnt = count_cnt;
                        next_prefix_cnt = prefix_cnt;
                        next_build_cnt = build_cnt;
                        next_copy_cnt = copy_cnt;
                        next_done = done;
                    end
                    load_cnt <= load_cnt + 1;

                S_FIND_MAX:
                    find_cnt = 1;
                    next_state = S_COUNT;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt + 1;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt;
                    next_done = done;

                S_COUNT:
                    count_cnt = 1;
                    next_state = S_PREFIX_SUM;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt + 1;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt;
                    next_done = done;

                S_PREFIX_SUM:
                    prefix_cnt = 1;
                    next_state = S_BUILD_OUTPUT;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt + 1;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt;
                    next_done = done;

                S_BUILD_OUTPUT:
                    build_cnt = 1;
                    next_state = S_COPY_OUTPUT;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt + 1;
                    next_copy_cnt = copy_cnt;
                    next_done = done;

                S_COPY_OUTPUT:
                    copy_cnt = 1;
                    next_state = S_DONE;
                    next_data_array = data_array;
                    next_out_array = out_array;
                    next_count_array = count_array;
                    next_max_val = max_val;
                    next_load_cnt = load_cnt;
                    next_find_cnt = find_cnt;
                    next_count_cnt = count_cnt;
                    next_prefix_cnt = prefix_cnt;
                    next_build_cnt = build_cnt;
                    next_copy_cnt = copy_cnt + 1;
                    next_done = done;

                S_DONE:
                    done <= 1'b1;
                    out_data <= out_array;
                    current_state <= S_IDLE;
            end
        end
    end
endmodule

