module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (
  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr_b_taken;
  logic [31:0] instr_jal_taken;
  logic [31:0] instr_jalr_taken;
  logic [31:0] instr_cb_taken;

  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign instr_jal_taken = instr_jal  & imm_jal_type[31];
  assign instr_jalr_taken = instr_jalr & imm_jalr_type[31];
  assign instr_cb_taken = instr_cb   & imm_cb_type[31];

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal_taken : branch_imm = imm_jal_type;
      instr_jalr_taken : branch_imm = imm_jalr_type;
      instr_b_taken : branch_imm = imm_b_type;
      instr_cb_taken : branch_imm = imm_cb_type;
      default    : branch_imm = 0;
    endcase

    if (fetch_valid_i)
      predict_branch_pc_o = fetch_pc_i + branch_imm;
    else
      predict_branch_pc_o = fetch_pc_i;
      predict_exception_o = 1;
      predict_branch_taken_o = 0;
      predict_branch_pc_o = 0;
    end

    case(1'b1)
      instr_jal_taken : predict_branch_taken_o = 1;
      instr_jalr_taken : predict_branch_taken_o = 1;
      instr_b_taken : predict_branch_taken_o = (imm_b_type[31] == 1) ? 1 : 0;
      instr_cb_taken : predict_branch_taken_o = (imm_cb_type[31] == 1) ? 1 : 0;
      default : predict_branch_taken_o = 0;
    endcase

    case(1'b1)
      instr_jal_taken : predict_branch_type_o = 3'h001;
      instr_jalr_taken : predict_branch_type_o = 3'h010;
      instr_b_taken : predict_branch_type_o = 3'h011;
      instr_cb_taken : predict_branch_type_o = 3'h101;
      default : predict_branch_type_o = 3'h000;
    endcase

    case(1'b1)
      instr_jal_taken : predict_branch_offset_o = imm_jal_type;
      instr_jalr_taken : predict_branch_offset_o = imm_jalr_type;
      instr_b_taken : predict_branch_offset_o = imm_b_type;
      instr_cb_taken : predict_branch_offset_o = imm_cb_type;
      default : predict_branch_offset_o = 0;
    endcase

    if (fetch_valid_i)
      predict_confidence_o = (imm_b_type[31] == 1) ? 8'd90 : 8'd50;
    else
      predict_confidence_o = 0;
    end
  end
  assign predict_exception_o = (fetch_pc_i[1:0] != 2'b00);
endmodule

module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;
  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  // Calculate branch immediate based on instruction type
  if (instr_jal) begin
      branch_imm = imm_jal_type;
  else if (instr_jalr) begin
      branch_imm = imm_jalr_type;
  else if (instr_b) begin
      // B-type branch immediate construction
      branch_imm = (imm_b_type + (16'h10000000_00000000)) - 1;
  else if (instr_cj) begin
      // Extract immediate from CJ instruction
      branch_imm = imm_cj_type;
  else if (instr_cb) begin
      // Extract immediate from CB instruction
      branch_imm = imm_cb_type;
  else begin
      branch_imm = 0;
  end

  // Determine branch taken flag based on instruction type and immediate
  instr_b_taken = 0;
  if (instr_jal || instr_jalr || instr_cj) begin
      instr_b_taken = 1;
  else if (instr_b) begin
      // For B-type branches, check sign bit of immediate
      instr_b_taken = (branch_imm[31] == 1);
  else if (instr_cb) begin
      // For CB-type branches, check sign bit of immediate
      instr_b_taken = (branch_imm[31] == 1);
  end

  // Calculate predicted branch target address
  predict_branch_pc_o = branch_imm + fetch_pc_i;

module static_branch_predict(
  input logic [31:0] fetch_rdata_i,
  input logic [31:0] fetch_pc_i,
  input logic [31:0] register_addr_i,
  input logic fetch_valid_i,
  output logic predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,
  output logic [7:0] predict_confidence_o,
  output logic predict_exception_o,
  output logic [2:0] predict_branch_type_o,
  output logic [31:0] predict_branch_offset_o
)

  logic [31:0] reg_addr;
  logic [32:0] imm_jal_type;
  logic [32:0] imm_jalr_type;
  logic [32:0] imm_b_type;
  logic [32:0] imm_cj_type;
  logic [32:0] imm_cb_type;
  logic [32:0] instr;

  logic instr_jal, instr_jalr, instr_b, instr_cj, instr_cb;
  logic instr_b_taken;

  // Decode instruction
  instr = fetch_rdata_i;

  // Determine branch type and calculate immediate values
  case(instr[6:0])
    7'h6F: instr_jal = 1; imm_jal_type = { {12(instr[31])}, instr[19:12], instr[20], instr[30:21], 1'b0 };
    7'h67: instr_jalr = 1; imm_jalr_type = {{20(instr[31])}, instr[31:20]} + register_addr_i;
    7'h63: instr_b = 1; imm_b_type = { {19(instr[31])}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };
    7'h67 | 7'h66: instr_cj = 1; imm_cj_type = { {20(instr[12])}, instr[12], instr[8], instr[10:9], instr[6], instr[7], instr[2], instr[11], instr[5:3], 1'b0 };
    7'h67 | 7'h65: instr_cb = 1; imm_cb_type = { {23(instr[12])}, instr[12], instr[6:5], instr[2], instr[11:10], instr[4:3], 1'b0 };
    default: instr_b_taken = 0;
  endcase

  // Calculate confidence levels
  if (instr_jal) predict_confidence_o = 100;
  else if (instr_jalr) predict_confidence_o = 100;
  else if (instr_b) predict_confidence_o = 90;
  else if (instr_cj) predict_confidence_o = 90;
  else if (instr_cb) predict_confidence_o = 90;
  else predict_confidence_o = 0;

  // Set prediction flags
  predict_branch_taken_o = (predict_confidence_o > 50);
  predict_branch_type_o = { instr_b, instr_cj, instr_cb, instr_jal, instr_jalr }[instr];
  predict_branch_offset_o = 0;
  if (instr_jal) predict_branch_offset_o = imm_jal_type;
  else if (instr_jalr) predict_branch_offset_o = imm_jalr_type;
  else if (instr_b) predict_branch_offset_o = imm_b_type;
  else if (instr_cj) predict_branch_offset_o = imm_cj_type;
  else if (instr_cb) predict_branch_offset_o = imm_cb_type;

  // Calculate target address
  predict_branch_pc_o = fetch_pc_i + predict_branch_offset_o;

  // Exception detection
  predict_exception_o = 0;
  if (!fetch_valid_i) predict_exception_o = 1;
  else if (instr_b_taken) predict_exception_o = 1;

endmodule

