`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
);
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
);
    input clock;
    input reset;
    input write_en;
    input read_en;
    input data_in;
    output empty;
    output full;
    output data_out;

    // Configuration parameters
    static const depth = 2 ** ADDR_WIDTH;
    static const pointer = 0;

    // Module state variables
    reg [DATA_WIDTH-1:0] data_FIFO [0:depth-1];
    reg pointer;

    // Output signals
    assign empty = (pointer == 0);
    assign full = (pointer == depth);
    assign data_out = (empty ? data_FIFO[0] : data_FIFO[pointer-1]);

    // Clock edge sensitivity
    always clock_edge begin
        if (reset) begin
            data_FIFO = { DATA_WIDTH'b0 };
            pointer = 0;
            empty = 1;
            full = 0;
        end else if (write_en) begin
            if (empty) begin
                data_FIFO[pointer] = data_in;
                pointer++;
                if (pointer == depth) pointer = 0;
            end
        end else if (read_en) begin
            if (full) begin
                data_out = data_FIFO[pointer];
                pointer--;
                if (pointer == -1) pointer = depth - 1;
            end
        end
    end
endmodule

module sync_lifo #(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
)(
    input wire clock,
    input wire reset,
    input wire write_en,
    input wire read_en,
    input wire [DATA_WIDTH-1:0] data_in,
    output wire error,
    output wire valid,
    output wire [DATA_WIDTH-1:0] data_out
);

    // Calculate depth of the LIFO using the address width
    localparam DEPTH = (1 << ADDR_WIDTH);

    // Registers for LIFO logic
    reg [DEPTH-1:0] ptr;
    reg [DEPTH-1:0] lifo_counter;
    reg [DATA_WIDTH-1:0] memory [DEPTH-1:0];
    reg [DATA_WIDTH-1:0] temp_data_out;
    integer i;

    // Error state flag
    wire error_occurred = 0;

    // Output assignments for empty and full flags
    assign empty = (lifo_counter == 0) ? 1'b1 : 1'b0;
    assign full  = (lifo_counter == DEPTH) ? 1'b1 : 1'b0;

    // Counter logic to track the number of elements in LIFO
    always @(posedge clock) begin
        if (reset) begin
            lifo_counter <= 0;
            ptr <= {ADDR_WIDTH {1'b0}};
        end else if (!full && write_en) begin
            lifo_counter <= lifo_counter + 1;
            ptr <= ptr + 1;
        end else if (!empty && read_en) begin
            lifo_counter <= lifo_counter - 1;
            ptr <= ptr - 1;
        end
    end

    // Memory write logic: writes data into the LIFO
    always @(posedge clock) begin
        if (reset) begin
            ptr <= {ADDR_WIDTH {1'b0}};
        end else if (write_en && !full) begin
            memory[ptr] <= data_in;
            ptr <= ptr + 1;
        end
    end

    // Memory read logic: reads data from the LIFO
    always @(posedge clock) begin
        if (reset) begin
            temp_data_out <= {DATA_WIDTH{1'b0}};
        end else if (read_en && !empty) begin
            temp_data_out <= memory[ptr - 1'b1];
            ptr <= ptr - 1;
        end
    end

    // Error handling and valid signal
    always @* begin
        if (write_en && lifo_counter == DEPTH) begin
            error <= 1'b1;
        end else if (read_en && lifo_counter == 0) begin
            error <= 1'b1;
            valid <= 0;
        end else if (read_en && empty) begin
            valid <= 1'b1;
        end else if (write_en && write_en) begin
            valid <= 1'b1;
        end
    end

    assign data_out = temp_data_out;
endmodule

output.rtl/thermostat.v:
module thermostat(
    input wire [5:0] i_temp_feedback,
    input wire i_fan_on,
    input wire i_enable,
    input wire i_fault,
    input wire i_rst,
    output reg [2:0] o_state,
    output reg [5:0] o_heater,
    output reg [5:0] o_aircon,
    output reg o_fan
);

    // State transition table
    reg [2:0] next_state;

    always @posedge i_clk) begin
        if (i_rst) begin
            o_state = 000;
            o_heater = 000000;
            o_aircon = 000000;
            o_fan = 0;
        elsif (i_fault) begin
            o_state = 000;
            o_heater = 000000;
            o_aircon = 000000;
            o_fan = 0;
        elsif (i_enable) begin
            case (o_state)
                000: 
                    if (i_temp_feedback[5] & 1) next_state = 011;
                    else if (i_temp_feedback[4] & 1) next_state = 010;
                    else if (i_temp_feedback[3] & 1) next_state = 001;
                    else if (i_temp_feedback[2] & 1) next_state = 100;
                    else if (i_temp_feedback[1] & 1) next_state = 101;
                    else if (i_temp_feedback[0] & 1) next_state = 110;
                    else next_state = 000;
                011: 
                    if (i_temp_feedback[5] & 1) next_state = 011;
                    else if (i_temp_feedback[4] & 1) next_state = 010;
                    else if (i_temp_feedback[3] & 1) next_state = 001;
                    else if (i_temp_feedback[2] & 1) next_state = 100;
                    else if (i_temp_feedback[1] & 1) next_state = 101;
                    else next_state = 110;
                010: 
                    if (i_temp_feedback[5] & 1) next_state = 011;
                    else if (i_temp_feedback[4] & 1) next_state = 010;
                    else if (i_temp_feedback[3] & 1) next_state = 001;
                    else if (i_temp_feedback[2] & 1) next_state = 100;
                    else if (i_temp_feedback[1] & 1) next_state = 101;
                    else next_state = 110;
                001: 
                    if (i_temp_feedback[5] & 1) next_state = 011;
                    else if (i_temp_feedback[4] & 1) next_state = 010;
                    else if (i_temp_feedback[3] & 1) next_state = 001;
                    else if (i_temp_feedback[2] & 1) next_state = 100;
                    else if (i_temp_feedback[1] & 1) next_state = 101;
                    else next_state = 110;
                100: 
                    if (i_temp_feedback[5] & 1) next_state = 101;
                    else if (i_temp_feedback[4] & 1) next_state = 100;
                    else if (i_temp_feedback[3] & 1) next_state = 010;
                    else if (i_temp_feedback[2] & 1) next_state = 001;
                    else if (i_temp_feedback[1] & 1) next_state = 110;
                    else next_state = 100;
                101: 
                    if (i_temp_feedback[5] & 1) next_state = 101;
                    else if (i_temp_feedback[4] & 1) next_state = 100;
                    else if (i_temp_feedback[3] & 1) next_state = 010;
                    else if (i_temp_feedback[2] & 1) next_state = 001;
                    else next_state = 110;
                110: 
                    if (i_temp_feedback[5] & 1) next_state = 101;
                    else if (i_temp_feedback[4] & 1) next_state = 100;
                    else if (i_temp_feedback[3] & 1) next_state = 010;
                    else if (i_temp_feedback[2] & 1) next_state = 001;
                    else next_state = 110;
                default next_state = 000;
            endcase
        else begin
            case (o_state)
                000: 
                    if (i_fan_on) o_fan = 1;
                    else o_fan = 0;
                    next_state = o_state;
                011: 
                    if (i_fan_on) o_fan = 1;
                    else o_fan = 0;
                    next_state = o_state;
                010: 
                    if (i_fan_on) o_fan = 1;
                    else o_fan = 0;
                    next_state = o_state;
                001: 
                    if (i_fan_on) o_fan = 1;
                    else o_fan = 0;
                    next_state = o_state;
                100: 
                    if (i_fan_on) o_fan = 1;
                    else o_fan = 0;
                    next_state = o_state;
                101: 
                    if (i_fan_on) o_fan = 1;
                    else o_fan = 0;
                    next_state = o_state;
                110: 
                    if (i_fan_on) o_fan = 1;
                    else o_fan = 0;
                    next_state = o_state;
                default next_state = o_state;
            endcase
        end
    );

    // Assign outputs
    o_state = next_state;
    o_heater = [ (o_state & 4'b110000) >> 3 : 1,
                  (o_state & 4'b011000) >> 2 : 1,
                  (o_state & 4'b001100) >> 1 : 1,
                  (o_state & 4'b000111) : 1,
                  0 : 0 ];
    o_aircon = [ (o_state & 4'b110000) >> 3 : 1,
                 (o_state & 4'b011000) >> 2 : 1,
                 (o_state & 4'b001100) >> 1 : 1,
                 (o_state & 4'b000111) : 1,
                 0 : 0 ];
    o_fan = o_fan;

    // Always ensure proper initialization
    always @* begin
        o_state = 000;
        o_heater = 000000;
        o_aircon = 000000;
        o_fan = 0;
    end
endmodule

output.rtl/ttc_counter_lite.sv:
module ttcounter_lite(
    input clock,
    input reset,
    input axi_addr,
    input axi_wdata,
    input axi_write_en,
    input axi_read_en,
    output axi_rdata,
    output interrupt
);

    // Registers
    register [31:0] count;
    register [31:0] match_value;
    register [31:0] reload_value;
    register [31:0] control;
    register [31:0] status;

    // Initial state
    initial begin
        // Initialize all registers to 0
        count = 0;
        match_value = 0;
        reload_value = 0;
        control = 0b0000_0000;
        status = 0b0000_0000;
        // Set default to non-interval mode, disable timer
        control = 0b0000_0000;
        // Set interval mode to off
        control |= (4'b0000);
        // Set match value to 0
        match_value = 0;
        // Set reload value to 0
        reload_value = 0;
        // Set enable to 0
        control |= (5'b00000);
        // Set interval mode to off
        control |= (6'b000000);
        // Set interrupt enable to 0
        control |= (7'b0000000);
        // Start the counter
        initial_state();
    end

    // Counter logic
    always clockbegin
        if (reset) 
            count = 0;
        else if (control & 0x40000000) // Enable bit is set
            if (!interval_mode) 
                count = count + 1;
            else 
                if (count == match_value) 
                    count = reload_value;
        end
    end

    // Match detection
    always 
        if (count == match_value) 
            match_flag = 1;
        else 
            match_flag = 0;
    end

    // Interrupt generation
    always clockbegin
        if (match_flag & interrupt_enable) 
            interrupt = 1;
        else 
            interrupt = 0;
        end
    end

    // AXI-Lite interfaces
    always 
        if (axi_write_en) 
            reload_value = axi_wdata;
        if (axi_read_en) 
            axi_rdata = count;
        end
    end

    // Status register
    always 
        if (match_flag) 
            status = 0x00000001;
        else 
            status = 0x00000000;
        end
    end

    // Initial block
    initial begin
        // Set initial state
        $display("Initial state setup complete");
    end

endmodule

output.rtl/unpack_one_hot.v:
module unpack_one_hot
(
    input sign,
    input size,
    input [2:0] one_hot_selector,
    input source_reg,
    output [511:0] destination_reg
);

    // Initialize destination register to zero
    destination_reg <= 0;

    // Determine the number of bits to unpack and the size of the destination segment
    case (one_hot_selector)
    // Case 001: unpack each bit into 8-bit segment
    3'b001:
        // Each bit is sign-extended to 8 bits
        size <= 8;
        // Unpack each bit into 8-bit segment
        for (i = 0; i < 256; i = i + 1) begin
            // Extract the ith bit from source_reg
            bit [7:0] bit_val = source_reg[i];
            // Sign-extend to 8 bits
            destination_reg[(i * 8) + 0:7] = (bit_val & 0x1) ? - (bit_val) : bit_val;
        end
        break;

    // Case 010: unpack each 2-bit segment into 8-bit segment
    3'b010:
        // Each 2-bit segment is zero-extended to 8 bits
        size <= 8;
        // Unpack each 2-bit segment into 8-bit segment
        for (i = 0; i < 128; i = i + 1) begin
            // Extract the 2-bit segment from source_reg
            bit [7:0] seg_val = source_reg[i * 2: i * 2 + 1];
            // Zero-extend to 8 bits
            destination_reg[(i * 8) + 0:7] = seg_val;
        end
        break;

    // Case 100: handle size-dependent behavior
    3'b100:
        // Determine the segment size based on 'size' input
        if (size == 1) begin
            // Each 8-bit segment is sign-extended to 16 bits
            size <= 16;
            for (i = 0; i < 32; i = i + 1) begin
                // Extract the 8-bit segment from source_reg
                bit [15:0] seg_val = source_reg[i * 8: i * 8 + 7];
                // Sign-extend to 16 bits
                destination_reg[(i * 16) + 0:15] = (seg_val & 0xFF) ? - (seg_val) : seg_val;
            end
        else begin
            // Each 4-bit segment is zero-extended to 8 bits
            size <= 8;
            for (i = 0; i < 64; i = i + 1) begin
                // Extract the 4-bit segment from source_reg
                bit [7:0] seg_val = source_reg[i * 4: i * 4 + 3];
                // Zero-extend to 8 bits
                destination_reg[(i * 8) + 0:7] = seg_val;
            end
        end
        break;

    // Default case: assign source_reg directly to destination_reg
    default:
        size <= 1;
        for (i = 0; i < 256; i = i + 1) begin
            // Assign each bit to destination_reg
            destination_reg[i] = source_reg[i];
        end
        break;

    endcase
endmodule

output.rtl/vending_machine.sv:
// State declarations
state state_state;
reg [4:0] item_price;
reg [4:0] change_amount;
reg [3:0] dispense_item_id;
reg error;
reg return_money;

// State transitions and logic
always @(posedge clk) begin
    case (state_state)
        IDLE: 
            if (item_button) begin
                state_state = ITEM_SELECTION;
                item_price = 0;
                change_amount = 0;
                dispense_item_id = 0;
            end
            else if (error) begin
                state_state = RETURN_MONEY;
                return_money = 1;
                error = 0;
            end
        ITEM_SELECTION: 
            if (item_selected) begin
                dispense_item_id = item_selected;
                item_price = item_price_table[item_selected];
                state_state = PAYMENT_VALIDATION;
            end
            else if (cancel) begin
                state_state = RETURN_MONEY;
                error = 1;
                return_money = 1;
            end
        PAYMENT_VALIDATION: 
            if (coin_input & 0b1111) begin
                coins_accumulated +== 1;
                if (coins_accumulated >= item_price) begin
                    state_state = DISPENSING_ITEM;
                    coins_accumulated = 0;
                end else begin
                    state_state = RETURN_MONEY;
                    error = 1;
                    return_money = 1;
                end
            end
        DISPENSING_ITEM: 
            dispense_item = 1;
            if (coins_accumulated > item_price) begin
                change_amount = coins_accumulated - item_price;
                state_state = RETURNCHANGE;
            else begin
                state_state = IDLE;
            end
        RETURNCHANGE: 
            return_change = 1;
            state_state = IDLE;
        RETURN_MONEY: 
            return_money = 0;
            state_state = IDLE;
    endcase
end

output.rtl/vga_controller.sv:
module vga_controller(
    input clock,
    input reset,
    input color_in,
    output hsync,
    output vsync,
    output red,
    output green,
    output blue,
    output next_x,
    output next_y,
    output sync,
    output blank
);

    // Horizontal State Machine
    reg [3:0] h_state = 3;
    reg h_counter = 0;
    // Vertical State Machine
    reg [3:0] v_state = 3;
    reg v_counter = 0;

    // Horizontal FSM
    always_ff (posedge clock) begin
        case (h_state)
            3: // Active
                h_counter = h_counter + 1;
                if (h_counter == 640) begin
                    h_state = 2;
                    hsync = 1;
                    blank = 0;
                end
            2: // Front Porch
                if (h_counter == 16) begin
                    h_state = 1;
                    hsync = 0;
                end
            1: // Sync Pulse
                h_counter = h_counter + 1;
                if (h_counter == 96) begin
                    h_state = 0;
                    vsync = 1;
                end
            0: // Back Porch
                if (h_counter == 48) begin
                    h_state = 3;
                    hsync = 0;
                end
            default:
                h_state = 3;
        end
    end

    // Vertical FSM
    always_ff (posedge clock) begin
        case (v_state)
            3: // Active
                v_counter = v_counter + 1;
                if (v_counter == 480) begin
                    v_state = 2;
                    vsync = 1;
                end
            2: // Front Porch
                if (v_counter == 10) begin
                    v_state = 1;
                    vsync = 0;
                end
            1: // Sync Pulse
                v_counter = v_counter + 1;
                if (v_counter == 2) begin
                    v_state = 0;
                    blank = 1;
                end
            0: // Back Porch
                if (v_counter == 33) begin
                    v_state = 3;
                    vsync = 0;
                end
            default:
                v_state = 3;
        end
    end

    // Color Control
    always clock begin
        case (h_state)
            3: // Active
                red = (color_in[7:5] << 3) | 8'd0;
                green = (color_in[4:2] << 3) | 8'd0;
                blue = (color_in[1:0] << 5) | 8'd0;
            default:
                red = 8'd0;
                green = 8'd0;
                blue = 8'd0;
        end
    end

    // Line Done Signal
    line_done = (h_state == 3 && h_counter == 640);

    // Blank Signal
    blank = (hsync == 0 && vsync == 0);

    // Synchronization Signals
    hsync = (h_state == 1 || h_state == 0);
    vsync = (v_state == 1 || v_state == 0);
    sync = 8'd0;

endmodule

module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,      // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state, // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;


    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    h_counter <= h_counter + 1;
                    hsync <= HIGH;
                    if (h_counter == H_ACTIVE-1) begin
                        h_state <= H_FRONT_STATE;
                    end
                end
                H_FRONT_STATE: begin
                    h_counter <= h_counter + 1;
                    if (h_counter == H_FRONT-1) begin
                        h_state <= H_PULSE_STATE;
                    end
                end
                H_PULSE_STATE: begin
