    module ControlUnit (
        input clk,
        input reset,
        input hit,
        input miss,
        input ready,
        output reg tlb_write_enable,
        output reg flush
    );
        reg [1:0] state;
        reg [1:0] tag;
        reg [1:0] page_table_entry;
        reg [1:0] physical_address;
        reg [1:0] valid_bits;
        reg [1:0] replacement_index;

        state = IDLE;
        always_comb begin
            if (reset) begin
                state = IDLE;
                tlb_write_enable = 0;
                flush = 0;
                tag = 0;
                page_table_entry = 0;
                physical_address = 0;
                valid_bits = 0;
                replacement_index = 0;
            end else if (hit) begin
                state = UPDATE;
                tlb_write_enable = 1;
                flush = 0;
            end else if (miss) begin
                state = FETCH;
                tlb_write_enable = 0;
                flush = 0;
            end else if (ready) begin
                state = UPDATE;
                tlb_write_enable = 1;
                flush = 0;
            end else begin
                state = IDLE;
                tlb_write_enable = 0;
                flush = 0;
            end
        end
    endmodule

